{
  "name": "OrderPro - Sistem Manajemen Order & Invoice",
  "description": "Aplikasi profesional untuk mencatat pesanan pelanggan, mengelola item barang, dan menghasilkan invoice yang dapat diunduh sebagai PDF atau gambar (JPG)."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum OrderStatus {
  PENDING = 'PENDING',
  PAID = 'PAID',
  SHIPPED = 'SHIPPED',
  CANCELLED = 'CANCELLED'
}

export interface OrderItem {
  id: string;
  name: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  invoiceNumber: string;
  customerName: string;
  customerEmail: string;
  customerAddress: string;
  orderDate: string;
  status: OrderStatus;
  items: OrderItem[];
  total: number;
  notes?: string;
}

export interface AppState {
  orders: Order[];
  activeOrder: Order | null;
  view: 'list' | 'create' | 'detail';
}

import { GoogleGenAI } from "@google/genai";
import { Order } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getSmartOrderSummary = async (order: Order): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan ringkasan singkat dan profesional untuk pesanan berikut dalam Bahasa Indonesia:
      Pelanggan: ${order.customerName}
      Invoice: ${order.invoiceNumber}
      Item: ${order.items.map(i => `${i.name} (${i.quantity}x)`).join(', ')}
      Total: Rp ${order.total.toLocaleString()}

      Tuliskan saran singkat apakah ada item pelengkap yang bisa ditawarkan kepada pelanggan ini berdasarkan item yang dibeli.`,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "Gagal menghasilkan ringkasan.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Maaf, asisten AI sedang tidak tersedia.";
  }
};

import React, { useState, useEffect } from 'react';
import { Plus, List, Search, Printer, Download, Trash2, Edit3, ChevronLeft, Package, Sparkles } from 'lucide-react';
import { Order, OrderStatus, OrderItem, AppState } from './types';
import OrderForm from './components/OrderForm';
import OrderList from './components/OrderList';
import InvoiceView from './components/InvoiceView';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    activeOrder: null,
    view: 'list',
  });

  const [searchQuery, setSearchQuery] = useState('');

  // Load initial data from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('orderpro_data');
    if (saved) {
      setState(prev => ({ ...prev, orders: JSON.parse(saved) }));
    }
  }, []);

  // Save to localStorage whenever orders change
  useEffect(() => {
    localStorage.setItem('orderpro_data', JSON.stringify(state.orders));
  }, [state.orders]);

  const handleCreateOrder = (newOrder: Order) => {
    setState(prev => ({
      ...prev,
      orders: [newOrder, ...prev.orders],
      view: 'list'
    }));
  };

  const handleDeleteOrder = (id: string) => {
    if (window.confirm('Hapus pesanan ini?')) {
      setState(prev => ({
        ...prev,
        orders: prev.orders.filter(o => o.id !== id)
      }));
    }
  };

  const handleViewOrder = (order: Order) => {
    setState(prev => ({ ...prev, activeOrder: order, view: 'detail' }));
  };

  const filteredOrders = state.orders.filter(order => 
    order.customerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    order.invoiceNumber.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Navigation Header */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div 
              className="flex items-center gap-2 cursor-pointer" 
              onClick={() => setState(prev => ({ ...prev, view: 'list', activeOrder: null }))}
            >
              <div className="bg-indigo-600 p-2 rounded-lg">
                <Package className="text-white w-6 h-6" />
              </div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">OrderPro</h1>
            </div>

            <div className="flex items-center gap-4">
              {state.view === 'list' && (
                <div className="relative hidden md:block">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
                  <input 
                    type="text" 
                    placeholder="Cari invoice atau pelanggan..."
                    className="pl-10 pr-4 py-2 bg-gray-100 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500 rounded-full text-sm w-64 transition-all"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
              )}

              <button 
                onClick={() => setState(prev => ({ ...prev, view: 'create' }))}
                className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg font-medium transition-colors shadow-sm shadow-indigo-200"
              >
                <Plus className="w-5 h-5" />
                <span>Order Baru</span>
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {state.view === 'list' && (
          <div className="animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
              <div>
                <h2 className="text-2xl font-bold text-gray-900">Daftar Pesanan</h2>
                <p className="text-gray-500 text-sm mt-1">Kelola semua transaksi dan pengiriman Anda</p>
              </div>
            </div>

            {filteredOrders.length > 0 ? (
              <OrderList 
                orders={filteredOrders} 
                onDelete={handleDeleteOrder}
                onView={handleViewOrder}
              />
            ) : (
              <div className="bg-white border-2 border-dashed border-gray-200 rounded-2xl p-12 text-center">
                <div className="bg-gray-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4">
                  <List className="text-gray-400 w-8 h-8" />
                </div>
                <h3 className="text-lg font-medium text-gray-900">Belum ada pesanan</h3>
                <p className="text-gray-500 mt-2 max-w-xs mx-auto">Mulai dengan membuat pesanan baru untuk pelanggan Anda.</p>
                <button 
                  onClick={() => setState(prev => ({ ...prev, view: 'create' }))}
                  className="mt-6 inline-flex items-center gap-2 text-indigo-600 font-semibold hover:underline"
                >
                  <Plus className="w-5 h-5" />
                  Buat Pesanan Pertama
                </button>
              </div>
            )}
          </div>
        )}

        {state.view === 'create' && (
          <div className="max-w-3xl mx-auto animate-in slide-in-from-bottom-4 duration-500">
            <button 
              onClick={() => setState(prev => ({ ...prev, view: 'list' }))}
              className="flex items-center gap-2 text-gray-500 hover:text-gray-800 mb-6 transition-colors"
            >
              <ChevronLeft className="w-5 h-5" />
              Kembali
            </button>
            <OrderForm onSubmit={handleCreateOrder} />
          </div>
        )}

        {state.view === 'detail' && state.activeOrder && (
          <div className="animate-in fade-in duration-500">
             <button 
              onClick={() => setState(prev => ({ ...prev, view: 'list', activeOrder: null }))}
              className="flex items-center gap-2 text-gray-500 hover:text-gray-800 mb-6 transition-colors"
            >
              <ChevronLeft className="w-5 h-5" />
              Kembali ke Daftar
            </button>
            <InvoiceView order={state.activeOrder} />
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-gray-200 py-6 text-center text-gray-400 text-xs">
        &copy; {new Date().getFullYear()} OrderPro System. Made with React & Gemini.
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Plus, Trash2, Save } from 'lucide-react';
import { Order, OrderItem, OrderStatus } from '../types';

interface OrderFormProps {
  onSubmit: (order: Order) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ onSubmit }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerEmail, setCustomerEmail] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [items, setItems] = useState<OrderItem[]>([
    { id: Math.random().toString(36).substr(2, 9), name: '', quantity: 1, price: 0 }
  ]);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', quantity: 1, price: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof OrderItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (item.quantity * item.price), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      invoiceNumber: `INV-${Date.now().toString().slice(-6)}`,
      customerName,
      customerEmail,
      customerAddress,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      total: calculateTotal(),
      notes
    };

    onSubmit(newOrder);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-gray-200 border border-gray-100 p-8">
      <h2 className="text-2xl font-bold text-gray-900 mb-8">Form Pesanan Baru</h2>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Nama Pelanggan</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Contoh: Budi Santoso"
              value={customerName}
              onChange={(e) => setCustomerName(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Email Pelanggan</label>
            <input 
              required
              type="email" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="budi@email.com"
              value={customerEmail}
              onChange={(e) => setCustomerEmail(e.target.value)}
            />
          </div>
          <div className="md:col-span-2 space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Alamat Pengiriman</label>
            <textarea 
              required
              rows={3}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Jl. Merdeka No. 123, Jakarta"
              value={customerAddress}
              onChange={(e) => setCustomerAddress(e.target.value)}
            />
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-gray-900">Daftar Barang</h3>
            <button 
              type="button"
              onClick={addItem}
              className="flex items-center gap-1 text-sm text-indigo-600 hover:text-indigo-700 font-semibold"
            >
              <Plus className="w-4 h-4" />
              Tambah Item
            </button>
          </div>

          <div className="space-y-3">
            {items.map((item, index) => (
              <div key={item.id} className="grid grid-cols-12 gap-3 items-end bg-gray-50 p-4 rounded-xl border border-gray-200">
                <div className="col-span-12 md:col-span-6 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Nama Barang</label>
                  <input 
                    required
                    type="text"
                    placeholder="Nama Barang"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.name}
                    onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                  />
                </div>
                <div className="col-span-4 md:col-span-2 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Qty</label>
                  <input 
                    required
                    type="number"
                    min="1"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.quantity}
                    onChange={(e) => updateItem(item.id, 'quantity', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-5 md:col-span-3 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Harga Satuan</label>
                  <input 
                    required
                    type="number"
                    min="0"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.price}
                    onChange={(e) => updateItem(item.id, 'price', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-3 md:col-span-1 flex justify-center pb-2">
                  <button 
                    type="button"
                    onClick={() => removeItem(item.id)}
                    className="text-red-400 hover:text-red-600 transition-colors"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Catatan (Opsional)</label>
            <textarea 
              rows={2}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Catatan tambahan untuk pesanan ini..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </div>

        <div className="pt-6 border-t border-gray-100 flex items-center justify-between">
          <div className="text-gray-500">
            Total Pembayaran: <span className="text-2xl font-bold text-gray-900">Rp {calculateTotal().toLocaleString()}</span>
          </div>
          <button 
            type="submit"
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-100"
          >
            <Save className="w-5 h-5" />
            Simpan Pesanan
          </button>
        </div>
      </form>
    </div>
  );
};

export default OrderForm;

import React from 'react';
import { Eye, Trash2, Calendar, User, FileText } from 'lucide-react';
import { Order, OrderStatus } from '../types';

interface OrderListProps {
  orders: Order[];
  onDelete: (id: string) => void;
  onView: (order: Order) => void;
}

const OrderList: React.FC<OrderListProps> = ({ orders, onDelete, onView }) => {
  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PAID: return 'bg-green-100 text-green-700';
      case OrderStatus.SHIPPED: return 'bg-blue-100 text-blue-700';
      case OrderStatus.CANCELLED: return 'bg-red-100 text-red-700';
      default: return 'bg-amber-100 text-amber-700';
    }
  };

  const getStatusLabel = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PAID: return 'Lunas';
      case OrderStatus.SHIPPED: return 'Dikirim';
      case OrderStatus.CANCELLED: return 'Batal';
      default: return 'Tertunda';
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Invoice / Tanggal</th>
              <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Pelanggan</th>
              <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Total</th>
              <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-gray-500 uppercase tracking-wider text-right">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {orders.map((order) => (
              <tr key={order.id} className="hover:bg-gray-50/50 transition-colors group">
                <td className="px-6 py-5">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-gray-900 flex items-center gap-1.5">
                      <FileText className="w-3.5 h-3.5 text-gray-400" />
                      {order.invoiceNumber}
                    </span>
                    <span className="text-xs text-gray-400 mt-1 flex items-center gap-1.5">
                      <Calendar className="w-3.5 h-3.5" />
                      {new Date(order.orderDate).toLocaleDateString('id-ID', { day: 'numeric', month: 'short', year: 'numeric' })}
                    </span>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <div className="flex flex-col">
                    <span className="text-sm font-medium text-gray-700 flex items-center gap-1.5">
                      <User className="w-3.5 h-3.5 text-gray-400" />
                      {order.customerName}
                    </span>
                    <span className="text-xs text-gray-400 truncate max-w-[150px]">{order.customerEmail}</span>
                  </div>
                </td>
                <td className="px-6 py-5">
                  <span className="text-sm font-bold text-gray-900">
                    Rp {order.total.toLocaleString()}
                  </span>
                </td>
                <td className="px-6 py-5">
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-semibold ${getStatusColor(order.status)}`}>
                    {getStatusLabel(order.status)}
                  </span>
                </td>
                <td className="px-6 py-5 text-right">
                  <div className="flex items-center justify-end gap-2">
                    <button 
                      onClick={() => onView(order)}
                      className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"
                      title="Lihat Invoice"
                    >
                      <Eye className="w-5 h-5" />
                    </button>
                    <button 
                      onClick={() => onDelete(order.id)}
                      className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      title="Hapus"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default OrderList;

import React, { useRef, useState, useEffect } from 'react';
import { Download, Printer, Share2, Sparkles, Image as ImageIcon, FileText } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const fetchSummary = async () => {
      setIsAiLoading(true);
      const summary = await getSmartOrderSummary(order);
      setAiSummary(summary);
      setIsAiLoading(false);
    };
    fetchSummary();
  }, [order]);

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${order.invoiceNumber}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2 });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const imgProps = pdf.getImageProperties(imgData);
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${order.invoiceNumber}.pdf`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pb-12">
      {/* Left: Invoice Display */}
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold text-gray-900">Preview Invoice</h3>
            <div className="flex gap-2">
                <button 
                  onClick={handleDownloadJPG}
                  className="p-2 bg-white border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 flex items-center gap-2 text-sm font-medium transition-colors"
                >
                  <ImageIcon className="w-4 h-4" />
                  JPG
                </button>
                <button 
                  onClick={handleDownloadPDF}
                  className="p-2 bg-indigo-600 text-white border border-indigo-600 rounded-lg hover:bg-indigo-700 flex items-center gap-2 text-sm font-medium transition-colors shadow-sm"
                >
                  <FileText className="w-4 h-4" />
                  PDF
                </button>
            </div>
        </div>

        {/* The actual Invoice Template */}
        <div 
          ref={invoiceRef}
          className="bg-white rounded-lg shadow-2xl p-10 md:p-16 text-gray-800 border border-gray-100 overflow-hidden"
          style={{ width: '100%', maxWidth: '800px', margin: '0 auto' }}
        >
          {/* Invoice Header */}
          <div className="flex justify-between items-start border-b-2 border-indigo-600 pb-8 mb-10">
            <div className="space-y-2">
              <div className="bg-indigo-600 text-white w-12 h-12 rounded-xl flex items-center justify-center mb-4">
                <span className="text-2xl font-black">OP</span>
              </div>
              <h1 className="text-3xl font-black tracking-tighter text-indigo-600">INVOICE</h1>
              <p className="text-gray-400 font-medium">{order.invoiceNumber}</p>
            </div>
            <div className="text-right space-y-1">
              <h2 className="text-lg font-bold text-gray-900">OrderPro Store</h2>
              <p className="text-sm text-gray-500">Jakarta Pusat, Indonesia</p>
              <p className="text-sm text-gray-500">support@orderpro.id</p>
              <p className="text-sm text-gray-500">+62 21 555 1234</p>
            </div>
          </div>

          {/* Billing Info */}
          <div className="grid grid-cols-2 gap-12 mb-12">
            <div>
              <h3 className="text-xs uppercase font-bold text-indigo-600 mb-3 tracking-widest">Tagihan Untuk</h3>
              <p className="font-bold text-gray-900 text-lg">{order.customerName}</p>
              <p className="text-gray-600 text-sm mt-1">{order.customerEmail}</p>
