// Always use the named parameter for apiKey and use the environment variable directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSmartOrderSummary = async (order: Order): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan ringkasan singkat dan profesional untuk pesanan berikut dalam Bahasa Indonesia:
      Pelanggan: ${order.customerName}
      Invoice: ${order.invoiceNumber}
      Item: ${order.items.map(i => `${i.name} (${i.quantity}x)`).join(', ')}
      Total: Rp ${order.total.toLocaleString()}

      Tuliskan saran singkat apakah ada item pelengkap yang bisa ditawarkan kepada pelanggan ini berdasarkan item yang dibeli.`,
      config: {
        temperature: 0.7,
      }
    });

    // Directly access the .text property from the response object.
    return response.text || "Gagal menghasilkan ringkasan.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Maaf, asisten AI sedang tidak tersedia.";
  }
};

