import React, { useState, useMemo } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, Calendar, User, 
  MapPin, Package, CreditCard, ChevronDown, Check, AlertCircle, Info
} from 'lucide-react';
import { AppState, Order, OrderItem, Customer, Product, OrderStatus, LocationType } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => void;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [downPayment, setDownPayment] = useState(0);
  const [notes, setNotes] = useState('');

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? product.priceLuarKota : product.priceJakarta;
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * item.qty);
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || orderItems.length === 0) return;

    const items: OrderItem[] = orderItems.map(oi => {
      const p = state.products.find(product => product.id === oi.productId)!;
      return {
        id: Math.random().toString(36).substr(2, 9),
        productId: p.id,
        name: p.name,
        quantity: oi.qty,
        unitPrice: calculateItemPrice(p, selectedCustomer.type)
      };
    });

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      invoiceNumber: `INV-${Date.now().toString().slice(-6)}`,
      customerId: selectedCustomer.id,
      customerName: selectedCustomer.name,
      customerEmail: selectedCustomer.email,
      customerType: selectedCustomer.type,
      customerAddress: selectedCustomer.address,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: calculatedSubtotal,
      downPayment,
      total: calculatedSubtotal - downPayment,
      notes
    };

    onAddOrder(newOrder);
    resetForm();
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setSelectedCustomerId('');
    setOrderItems([]);
    setDownPayment(0);
    setNotes('');
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Order Masuk</h2>
          <p className="text-slate-500 text-sm">Gunakan data Master Pelanggan & Barang untuk membuat order</p>
        </div>
        <button 
          onClick={() => setIsFormOpen(!isFormOpen)}
          className="bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100"
        >
          <Plus size={18} />
          Buat Order Baru
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-100 p-8 animate-in slide-in-from-top-4 duration-300">
           <form onSubmit={handleSubmit} className="space-y-8">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Customer Select */}
                <div className="space-y-4">
                  <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <User size={16} /> 1. Pilih Pelanggan
                  </h3>
                  <select 
                    required
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-medium"
                    value={selectedCustomerId}
                    onChange={e => setSelectedCustomerId(e.target.value)}
                  >
                    <option value="">-- Cari Pelanggan --</option>
                    {state.customers.map(c => (
                      <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                    ))}
                  </select>
                  {selectedCustomer && (
                    <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 space-y-1">
                      <p className="text-xs font-bold text-indigo-400 uppercase">Informasi Lokasi</p>
                      <p className="text-sm font-bold text-indigo-900">{selectedCustomer.type}</p>
                      <p className="text-xs text-indigo-600/70">{selectedCustomer.address}</p>
                      <div className="flex items-center gap-1.5 mt-2 text-[10px] bg-white w-fit px-2 py-0.5 rounded-full text-indigo-600 border border-indigo-100">
                        <Info size={10} /> Harga akan disesuaikan otomatis
                      </div>
                    </div>
                  )}
                </div>

                {/* Items Select */}
                <div className="space-y-4">
                   <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <Package size={16} /> 2. Tambah Barang
                  </h3>
                  <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border transition-all ${
                          existing ? 'bg-indigo-50 border-indigo-200' : 'bg-slate-50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-2">
                             <p className="text-sm font-bold text-slate-800 truncate">{p.name}</p>
                             <p className="text-[10px] text-slate-500">
                               Harga {selectedCustomer?.type || 'Jakarta'}: 
                               Rp {(selectedCustomer?.type === LocationType.LUAR_KOTA ? p.priceLuarKota : p.priceJakarta).toLocaleString()}
                             </p>
                           </div>
                           <div className="flex items-center gap-2 shrink-0">
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${
                                 existing ? 'bg-indigo-600 text-white' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-500 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={16} /> : <Plus size={16} />}
                             </button>
                             {existing && (
