             <div className="flex items-center justify-between bg-slate-900 p-6 rounded-2xl text-white shadow-xl shadow-slate-200">
               <div>
                  <div className="flex items-center gap-4 text-slate-400 text-sm mb-1 font-medium">
                    <span>Subtotal: Rp {calculatedSubtotal.toLocaleString()}</span>
