                <td className="px-6 py-4">
                  <p className="text-sm font-semibold text-slate-700">{o.customerName}</p>
                </td>
                <td className="px-6 py-4">
                  <span className={`inline-flex px-2 py-0.5 rounded-full text-[10px] font-bold ${
