import React, { useMemo } from 'react';
import { AppState } from '../types';
import { Package, Users, TrendingUp, ShoppingBag, Trophy, History } from 'lucide-react';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  // Logic: Barang Paling Laku
  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};

    state.orders.forEach(order => {
      order.items.forEach(item => {
        if (!salesMap[item.productId]) {
          salesMap[item.productId] = { name: item.name, qty: 0 };
        }
        salesMap[item.productId].qty += item.quantity;
      });
    });

    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [state.orders]);

  // Logic: Laporan Pelanggan
  const customerReports = useMemo(() => {
    return state.customers.map(customer => {
      const orders = state.orders.filter(o => o.customerId === customer.id);
      const itemsBought = new Set<string>();
      orders.forEach(o => o.items.forEach(i => itemsBought.add(i.name)));

      return {
        ...customer,
        orderCount: orders.length,
        itemsList: Array.from(itemsBought).join(', ') || '-'
      };
    }).sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, state.orders]);

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Top Products Section */}
      <section>
        <div className="flex items-center gap-3 mb-6">
          <div className="bg-amber-100 p-2 rounded-lg">
            <Trophy className="text-amber-600 w-5 h-5" />
          </div>
          <h3 className="text-xl font-bold text-slate-800">Barang Paling Laku</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {productSales.slice(0, 6).map((item, index) => (
            <div key={index} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="text-2xl font-black text-slate-100">0{index + 1}</div>
                <div>
                  <p className="font-bold text-slate-800">{item.name}</p>
                  <p className="text-xs text-slate-400">Total Terjual</p>
                </div>
              </div>
              <div className="bg-slate-50 px-3 py-1 rounded-full text-sm font-black text-indigo-600">
                {item.qty} pcs
              </div>
            </div>
          ))}
          {productSales.length === 0 && (
            <div className="col-span-full py-10 text-center text-slate-400 bg-white rounded-2xl border border-dashed border-slate-200">
              Belum ada data penjualan.
            </div>
          )}
        </div>
      </section>

      {/* Customer Insights Section */}
      <section>
