import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, FileText, 
  Package, BarChart3
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType, LocationType, OrderStatus } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);

  // Persistence Logic
  useEffect(() => {
    const savedData = localStorage.getItem('orderpro_v2_data');
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        // Migration: ensure old orders have payments array
        const migratedOrders = parsed.orders.map((o: any) => ({
          ...o,
          payments: o.payments || (o.downPayment > 0 ? [{ id: 'init', amount: o.downPayment, date: o.orderDate, note: 'Initial DP' }] : [])
        }));
        setState({ ...parsed, orders: migratedOrders });
      } catch (e) {
        console.error("Failed to load data", e);
      }
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (!isLoading) {
      localStorage.setItem('orderpro_v2_data', JSON.stringify(state));
    }
  }, [state, isLoading]);

  const setView = (view: ViewType) => setState(prev => ({ ...prev, view, activeOrder: null }));

  const addCustomer = (c: Customer) => setState(prev => ({ ...prev, customers: [c, ...prev.customers] }));
  const addProduct = (p: Product) => setState(prev => ({ ...prev, products: [p, ...prev.products] }));
  const addOrder = (o: Order) => setState(prev => ({ ...prev, orders: [o, ...prev.orders], view: 'orders' }));
  const updateOrder = (updated: Order) => setState(prev => ({
    ...prev,
    orders: prev.orders.map(o => o.id === updated.id ? updated : o)
  }));

  const deleteCustomer = (id: string) => setState(prev => ({ ...prev, customers: prev.customers.filter(c => c.id !== id) }));
  const deleteProduct = (id: string) => setState(prev => ({ ...prev, products: prev.products.filter(p => p.id !== id) }));
  const deleteOrder = (id: string) => setState(prev => ({ ...prev, orders: prev.orders.filter(o => o.id !== id) }));

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (isLoading) return <div className="min-h-screen flex items-center justify-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col sticky top-0 h-screen">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Package className="text-white w-6 h-6" />
          </div>
          <span className="text-xl font-bold text-white tracking-tight">OrderPro AI</span>
        </div>

        <nav className="flex-1 p-4 space-y-2 mt-4">
          <NavItem 
            icon={<LayoutDashboard size={20} />} 
            label="Dashboard" 
            active={state.view === 'dashboard'} 
            onClick={() => setView('dashboard')} 
          />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase tracking-wider text-slate-500">Master Data</div>
          <NavItem 
            icon={<Users size={20} />} 
            label="Pelanggan" 
            active={state.view === 'customers'} 
            onClick={() => setView('customers')} 
          />
          <NavItem 
            icon={<Box size={20} />} 
            label="Barang" 
            active={state.view === 'products'} 
            onClick={() => setView('products')} 
          />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase tracking-wider text-slate-500">Transaksi</div>
          <NavItem 
            icon={<ShoppingCart size={20} />} 
            label="Order Masuk" 
            active={state.view === 'orders'} 
            onClick={() => setView('orders')} 
          />
          <NavItem 
            icon={<BarChart3 size={20} />} 
            label="Laporan" 
            active={state.view === 'reports'} 
            onClick={() => setView('reports')} 
          />
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="bg-slate-800/50 rounded-xl p-3 flex items-center gap-3">
            <div className="w-8 h-8 rounded-full bg-indigo-500 flex items-center justify-center text-xs font-bold text-white">AD</div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-white truncate">Admin Toko</p>
              <p className="text-[10px] text-slate-500 truncate">Premium Plan</p>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto">
        <header className="bg-white border-b border-slate-200 h-16 flex items-center px-8 sticky top-0 z-30 justify-between">
           <h2 className="text-lg font-semibold text-slate-800 capitalize">
             {state.view.replace('_', ' ')}
           </h2>
           <div className="text-sm text-slate-400">
             {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
           </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto">
          {state.view === 'dashboard' && (
            <Dashboard state={state} onNavigate={setView} />
          )}

          {state.view === 'customers' && (
            <CustomerManager customers={state.customers} onAdd={addCustomer} onDelete={deleteCustomer} />
          )}

          {state.view === 'products' && (
            <ProductManager products={state.products} onAdd={addProduct} onDelete={deleteProduct} />
          )}

          {state.view === 'orders' && (
            <OrderManager 
              state={state} 
              onAddOrder={addOrder}
              onUpdateOrder={updateOrder}
              onDeleteOrder={deleteOrder} 
              onViewInvoice={viewInvoice}
            />
          )}

          {state.view === 'reports' && (
            <Reports state={state} />
          )}

          {state.view === 'invoice_detail' && state.activeOrder && (
            <div className="animate-in fade-in duration-300">
               <button 
                onClick={() => setView('orders')}
                className="flex items-center gap-2 text-slate-500 hover:text-slate-800 mb-6 transition-colors font-medium text-sm"
              >
                ← Kembali ke Order
              </button>
              <InvoiceView order={state.activeOrder} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

