import React, { useMemo, useState } from 'react';
import { AppState, LocationType } from '../types';
import { Package, Users, TrendingUp, History, Trophy, Filter, Calendar, Search } from 'lucide-react';

interface ReportsProps {
  state: AppState;
}

type TimeRange = 'all' | 'week' | 'month' | 'year';

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const [timeRange, setTimeRange] = useState<TimeRange>('all');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      // Time Filter
      const orderDate = new Date(order.orderDate);
      const now = new Date();
      let matchesTime = true;
      if (timeRange === 'week') {
        const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        matchesTime = orderDate >= weekAgo;
      } else if (timeRange === 'month') {
        matchesTime = orderDate.getMonth() === now.getMonth() && orderDate.getFullYear() === now.getFullYear();
      } else if (timeRange === 'year') {
        matchesTime = orderDate.getFullYear() === now.getFullYear();
      }

      // Customer Filter
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;

      // Product Filter
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);

      return matchesTime && matchesCustomer && matchesProduct;
    });
  }, [state.orders, timeRange, filterCustomer, filterProduct]);

  // Logic: Barang Paling Laku
  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};

    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) {
          salesMap[item.productId] = { name: item.name, qty: 0 };
        }
        salesMap[item.productId].qty += item.quantity;
      });
    });

    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  // Logic: Laporan Pelanggan
  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const itemsBought = new Set<string>();
        orders.forEach(o => o.items.forEach(i => itemsBought.add(i.name)));
        const totalSpent = orders.reduce((sum, o) => sum + o.total + o.downPayment, 0);

        return {
          ...customer,
          orderCount: orders.length,
          totalSpent,
          itemsList: Array.from(itemsBought).join(', ') || '-'
        };
      })
      .filter(c => c.orderCount > 0 || filterCustomer !== 'all')
      .sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, filteredOrders, filterCustomer]);

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Filter Bar */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Calendar size={12} /> Periode Waktu
          </label>
          <select 
            className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-100 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500"
            value={timeRange}
            onChange={(e) => setTimeRange(e.target.value as TimeRange)}
          >
            <option value="all">Semua Waktu</option>
            <option value="week">Minggu Ini (7 Hari Terakhir)</option>
            <option value="month">Bulan Ini</option>
            <option value="year">Tahun Ini</option>
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Users size={12} /> Filter Pelanggan
          </label>
          <select 
            className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-100 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500"
            value={filterCustomer}
            onChange={(e) => setFilterCustomer(e.target.value)}
          >
            <option value="all">Semua Pelanggan</option>
            {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Package size={12} /> Filter Barang
          </label>
          <select 
