import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, User, 
  Package, Check, Info, Edit3, MoreVertical, X, CreditCard
} from 'lucide-react';
import { AppState, Order, OrderItem, Customer, Product, OrderStatus, LocationType, PaymentRecord } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => void;
  onUpdateOrder: (o: Order) => void;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onUpdateOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);

  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);

  // Sync form when editing
  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId);
      setOrderItems(editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })));
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setIsFormOpen(true);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? product.priceLuarKota : product.priceJakarta;
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * item.qty);
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + p.amount, 0);
  }, [payments]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || orderItems.length === 0) return;

    const items: OrderItem[] = orderItems.map(oi => {
      const p = state.products.find(product => product.id === oi.productId)!;
      return {
        id: Math.random().toString(36).substr(2, 9),
        productId: p.id,
        name: p.name,
        quantity: oi.qty,
        unitPrice: calculateItemPrice(p, selectedCustomer.type)
      };
    });

    const orderData: Order = {
      id: editingOrder ? editingOrder.id : Math.random().toString(36).substr(2, 9),
      invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
      customerId: selectedCustomer.id,
      customerName: selectedCustomer.name,
      customerEmail: selectedCustomer.email,
      customerType: selectedCustomer.type,
      customerAddress: selectedCustomer.address,
      orderDate: editingOrder ? editingOrder.orderDate : new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: calculatedSubtotal,
      downPayment: currentTotalPaid,
      payments,
      total: calculatedSubtotal - currentTotalPaid,
      notes
    };

    if (editingOrder) {
      onUpdateOrder(orderData);
    } else {
      onAddOrder(orderData);
    }
    resetForm();
  };

  const addPayment = () => {
    if (newPaymentAmount <= 0) return;
    const newRecord: PaymentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      amount: newPaymentAmount,
      date: new Date().toISOString(),
      note: newPaymentNote || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
    };
    setPayments([...payments, newRecord]);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setShowPaymentInput(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Order Masuk</h2>
          <p className="text-slate-500 text-sm">Gunakan data Master Pelanggan & Barang untuk membuat order</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100"
        >
          <Plus size={18} />
          Buat Order Baru
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-100 p-8 animate-in slide-in-from-top-4 duration-300">
           <div className="flex justify-between items-center mb-8">
             <h3 className="text-xl font-black text-slate-900">{editingOrder ? 'Edit Pesanan' : 'Form Pesanan Baru'}</h3>
             <button onClick={resetForm} className="p-2 hover:bg-slate-50 rounded-full text-slate-400"><X size={20}/></button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-8">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Customer Select */}
                <div className="space-y-4">
                  <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <User size={16} /> 1. Pilih Pelanggan
                  </h3>
                  <select 
                    required
                    disabled={!!editingOrder}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-medium disabled:opacity-50"
                    value={selectedCustomerId}
                    onChange={e => setSelectedCustomerId(e.target.value)}
                  >
                    <option value="">-- Cari Pelanggan --</option>
                    {state.customers.map(c => (
                      <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                    ))}
                  </select>
                  {selectedCustomer && (
                    <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 space-y-1">
                      <p className="text-xs font-bold text-indigo-400 uppercase">Informasi Lokasi</p>
                      <p className="text-sm font-bold text-indigo-900">{selectedCustomer.type}</p>
                      <p className="text-xs text-indigo-600/70">{selectedCustomer.address}</p>
                    </div>
                  )}
                </div>

                {/* Items Select */}
                <div className="space-y-4">
                   <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    <Package size={16} /> 2. Kelola Barang
                  </h3>
                  <div className="space-y-3 max-h-[300px] overflow-y-auto pr-2">
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl border transition-all ${
                          existing ? 'bg-indigo-50 border-indigo-200' : 'bg-slate-50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-2">
                             <p className="text-sm font-bold text-slate-800 truncate">{p.name}</p>
                             <p className="text-[10px] text-slate-500 italic">
                               Rp {(selectedCustomer?.type === LocationType.LUAR_KOTA ? p.priceLuarKota : p.priceJakarta).toLocaleString()}
                             </p>
                           </div>
                           <div className="flex items-center gap-2 shrink-0">
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${
                                 existing ? 'bg-indigo-600 text-white' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-500 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={16} /> : <Plus size={16} />}
                             </button>
                             {existing && (
                               <input 
                                 type="number"
                                 min="1"
                                 className="w-12 px-1 py-1 rounded-lg border border-indigo-200 text-xs font-bold text-center outline-none focus:ring-1 focus:ring-indigo-500"
                                 value={existing.qty}
                                 onChange={e => {
                                   const val = parseInt(e.target.value) || 1;
                                   setOrderItems(orderItems.map(i => i.productId === p.id ? { ...i, qty: val } : i));
                                 }}
                               />
                             )}
                           </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6 border-t border-slate-100">
                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                      <CreditCard size={16} /> 3. Pembayaran / DP
                    </h3>
                    <button 
                      type="button" 
                      onClick={() => setShowPaymentInput(!showPaymentInput)}
                      className="text-[10px] font-black text-indigo-600 hover:underline"
                    >
                      + Tambah DP {payments.length > 0 ? 'Lagi' : ''}
                    </button>
                  </div>

                  {showPaymentInput && (
                    <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 space-y-3 animate-in fade-in duration-200">
                      <div className="grid grid-cols-2 gap-2">
                        <input 
                          type="number"
                          placeholder="Jumlah Rp"
                          className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
                          value={newPaymentAmount || ''}
                          onChange={e => setNewPaymentAmount(Number(e.target.value))}
                        />
                        <input 
                          type="text"
                          placeholder="Catatan (opsional)"
                          className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
                          value={newPaymentNote}
                          onChange={e => setNewPaymentNote(e.target.value)}
                        />
                      </div>
                      <div className="flex gap-2">
                        <button 
                          type="button" 
                          onClick={addPayment}
                          className="bg-indigo-600 text-white px-4 py-1.5 rounded-lg text-xs font-bold"
                        >
                          Simpan DP
                        </button>
                        <button 
                          type="button" 
                          onClick={() => setShowPaymentInput(false)}
                          className="text-slate-400 text-xs font-bold"
                        >
                          Batal
                        </button>
                      </div>
                    </div>
                  )}

                  <div className="space-y-2">
                    {payments.map((p, idx) => (
                      <div key={p.id} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600">
                            <Check size={14}/>
                          </div>
                          <div>
                            <p className="text-xs font-bold text-slate-800">{p.note}</p>
                            <p className="text-[10px] text-slate-400">{new Date(p.date).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <p className="text-sm font-black text-slate-800">Rp {p.amount.toLocaleString()}</p>
                      </div>
                    ))}
                    {payments.length === 0 && <p className="text-xs text-slate-400 italic py-2">Belum ada pembayaran masuk</p>}
                  </div>
                </div>

                <div className="space-y-4">
                  <h3 className="text-sm font-bold text-slate-800 uppercase tracking-widest flex items-center gap-2">
                    Catatan
                  </h3>
                  <textarea 
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none resize-none h-[120px]"
                    placeholder="Contoh: Kirim ekspedisi JNT, Packing kayu..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
             </div>

             <div className="flex items-center justify-between bg-slate-900 p-6 rounded-2xl text-white shadow-xl shadow-slate-200 mt-8">
               <div>
                  <div className="flex items-center gap-4 text-slate-400 text-[11px] mb-1 font-bold uppercase tracking-widest">
                    <span>Subtotal: Rp {calculatedSubtotal.toLocaleString()}</span>
                    <span>•</span>
                    <span>Total DP: Rp {currentTotalPaid.toLocaleString()}</span>
                  </div>
                  <h4 className="text-2xl font-black">
                    Sisa Tagihan: <span className="text-indigo-400">Rp {(calculatedSubtotal - currentTotalPaid).toLocaleString()}</span>
                  </h4>
               </div>
               <div className="flex gap-3">
                 <button 
                  type="submit"
                  disabled={!selectedCustomerId || orderItems.length === 0}
                  className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-8 py-3 rounded-xl font-bold text-sm shadow-lg shadow-indigo-900/20 transition-all flex items-center gap-2"
                 >
                   {editingOrder ? 'Simpan Perubahan' : 'Simpan & Buat Invoice'}
                 </button>
               </div>
             </div>
           </form>
        </div>
      )}

      {/* List Orders */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-widest">
            <tr>
              <th className="px-6 py-4">Nomor Order</th>
              <th className="px-6 py-4">Pelanggan</th>
              <th className="px-6 py-4 text-right">Total Tagihan</th>
              <th className="px-6 py-4 text-right">Sisa Bayar</th>
              <th className="px-6 py-4 text-center">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {state.orders.map(o => (
              <tr key={o.id} className="hover:bg-slate-50 transition-colors group">
                <td className="px-6 py-4">
                  <div>
                    <p className="text-sm font-bold text-slate-800">{o.invoiceNumber}</p>
                    <p className="text-[10px] text-slate-400 uppercase font-medium">{new Date(o.orderDate).toLocaleDateString()}</p>
