                </td>
                <td className="px-6 py-4">
                  <p className="text-sm font-semibold text-slate-700">{o.customerName}</p>
                  <span className={`inline-flex px-1.5 py-0.5 rounded text-[9px] font-black uppercase ${
                    o.customerType === LocationType.JAKARTA ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'
                  }`}>
                    {o.customerType}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="text-sm font-bold text-slate-800">
                    Rp {o.subtotal.toLocaleString()}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className={`text-sm font-black ${o.total <= 0 ? 'text-emerald-500' : 'text-slate-800'}`}>
                    Rp {o.total.toLocaleString()}
                    {o.downPayment > 0 && o.total > 0 && <span className="ml-2 text-[10px] text-indigo-400 font-bold tracking-tighter">(DP {o.payments.length}x)</span>}
                    {o.total <= 0 && <span className="ml-2 text-[9px] uppercase tracking-widest font-black">Lunas</span>}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex justify-center gap-1">
                    <button 
                      onClick={() => onViewInvoice(o)}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-lg transition-all"
                      title="Lihat Nota"
                    >
                      <Eye size={18} />
                    </button>
                    <button 
                      onClick={() => setEditingOrder(o)}
                      className="p-2 text-slate-400 hover:text-amber-600 hover:bg-white rounded-lg transition-all"
                      title="Edit Pesanan / Tambah DP"
                    >
                      <Edit3 size={18} />
                    </button>
                    <button 
                      onClick={() => { if(confirm('Hapus order ini?')) onDeleteOrder(o.id) }}
                      className="p-2 text-slate-400 hover:text-red-500 hover:bg-white rounded-lg transition-all"
                      title="Hapus"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
             {state.orders.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                  <ShoppingCart size={40} className="mx-auto mb-3 opacity-20" />
                  <p className="text-sm font-medium">Belum ada daftar transaksi</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default OrderManager;

import React, { useRef, useState, useEffect } from 'react';
import { Download, Printer, Share2, Sparkles, Image as ImageIcon, FileText, CheckCircle2 } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const fetchSummary = async () => {
      setIsAiLoading(true);
      const summary = await getSmartOrderSummary(order);
      setAiSummary(summary);
      setIsAiLoading(false);
    };
    fetchSummary();
  }, [order]);

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${order.invoiceNumber}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2, useCORS: true });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${order.invoiceNumber}.pdf`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pb-12">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold text-slate-800">Preview Nota</h3>
            <div className="flex gap-2">
                <button 
                  onClick={handleDownloadJPG}
                  className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 flex items-center gap-2 text-xs font-bold transition-all shadow-sm"
                >
                  <ImageIcon className="w-4 h-4" />
                  Download JPG
                </button>
                <button 
                  onClick={handleDownloadPDF}
