                          <div className="w-7 h-7 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600">
                            <Check size={12}/>
                          </div>
                          <div>
                            <p className="text-[11px] font-bold text-slate-800">{p.note}</p>
                            <p className="text-[9px] text-slate-400">{new Date(p.date).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <p className="text-xs font-black text-slate-800">Rp {p.amount.toLocaleString()}</p>
