import React, { useMemo, useState } from 'react';
import { AppState } from '../types';
import { Package, Users, TrendingUp, History, Trophy, Calendar } from 'lucide-react';

interface ReportsProps {
  state: AppState;
}

type TimeRange = 'all' | 'week' | 'month' | 'year';

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const [timeRange, setTimeRange] = useState<TimeRange>('all');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      const now = new Date();
      let matchesTime = true;
      if (timeRange === 'week') {
        const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        matchesTime = orderDate >= weekAgo;
      } else if (timeRange === 'month') {
        matchesTime = orderDate.getMonth() === now.getMonth() && orderDate.getFullYear() === now.getFullYear();
      } else if (timeRange === 'year') {
        matchesTime = orderDate.getFullYear() === now.getFullYear();
      }
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);
      return matchesTime && matchesCustomer && matchesProduct;
    });
  }, [state.orders, timeRange, filterCustomer, filterProduct]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + o.subtotal, 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0 || filterCustomer !== 'all')
      .sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, filteredOrders, filterCustomer]);

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20 md:pb-0">
      {/* Filter Bar */}
      <div className="bg-white p-4 md:p-6 rounded-2xl shadow-sm border border-slate-100 grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="space-y-1">
          <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Calendar size={10} /> Periode
          </label>
          <select 
            className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-100 text-xs font-medium outline-none"
            value={timeRange}
            onChange={(e) => setTimeRange(e.target.value as TimeRange)}
          >
            <option value="all">Semua Waktu</option>
            <option value="week">7 Hari Terakhir</option>
            <option value="month">Bulan Ini</option>
            <option value="year">Tahun Ini</option>
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Users size={10} /> Pelanggan
          </label>
          <select 
            className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-100 text-xs font-medium outline-none"
            value={filterCustomer}
            onChange={(e) => setFilterCustomer(e.target.value)}
          >
            <option value="all">Semua Pelanggan</option>
            {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-1">
            <Package size={10} /> Barang
          </label>
          <select 
            className="w-full px-3 py-2 rounded-xl bg-slate-50 border border-slate-100 text-xs font-medium outline-none"
            value={filterProduct}
            onChange={(e) => setFilterProduct(e.target.value)}
          >
            <option value="all">Semua Barang</option>
            {state.products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-indigo-600 rounded-2xl md:rounded-3xl p-6 md:p-8 text-white shadow-xl">
             <TrendingUp className="mb-4 opacity-50" size={24} />
             <p className="text-indigo-100 text-[10px] font-bold uppercase">Total Penjualan</p>
             <h3 className="text-2xl md:text-3xl font-black mt-1">
               Rp {filteredOrders.reduce((sum, o) => sum + o.subtotal, 0).toLocaleString()}
             </h3>
          </div>

          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
             <div className="flex items-center gap-3 mb-4">
                <Trophy className="text-amber-500" size={18} />
                <h4 className="font-bold text-slate-800 text-sm">Paling Laris</h4>
             </div>
             <div className="space-y-3">
               {productSales.slice(0, 5).map((p, i) => (
                 <div key={i} className="flex items-center justify-between">
                   <p className="text-xs font-bold text-slate-700 truncate pr-2">{p.name}</p>
                   <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full shrink-0">{p.qty}x</span>
                 </div>
               ))}
               {productSales.length === 0 && <p className="text-center text-slate-400 py-4 text-[10px] italic">Tidak ada data</p>}
             </div>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="flex items-center gap-3">
             <History className="text-indigo-600" size={18} />
             <h4 className="font-bold text-slate-800 text-md">Detail Belanja</h4>
          </div>
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden overflow-x-auto">
             <table className="w-full text-left min-w-[400px]">
                <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase">
                  <tr>
                    <th className="px-4 py-3">Nama</th>
                    <th className="px-4 py-3 text-center">Orders</th>
                    <th className="px-4 py-3 text-right">Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {customerReports.map((c, i) => (
                    <tr key={i} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-3 text-xs font-bold text-slate-800">{c.name}</td>
                      <td className="px-4 py-3 text-center">
                        <span className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded-full">{c.orderCount}</span>
                      </td>
                      <td className="px-4 py-3 text-right text-xs font-black text-slate-800">
                        Rp {c.totalSpent.toLocaleString()}
                      </td>
                    </tr>
                  ))}
                </tbody>
             </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import { createClient } from '@supabase/supabase-js';

// Pastikan environment variable ini tersedia di environment Anda
const supabaseUrl = process.env.SUPABASE_URL || '';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || '';

