import { createClient } from '@supabase/supabase-js';

// Kredensial Supabase dari pengguna
const supabaseUrl = 'https://kedvjiytvgsvabfbedbp.supabase.co';
const supabaseAnonKey = 'sb_publishable_Z71arHe_bRMPSrPfyChNwQ_t-CWcg0d';

// Inisialisasi client
export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

// Helper untuk mengecek apakah tabel tersedia
export const checkSupabaseConnection = async () => {
  if (!supabase) return false;
  try {
    const { error } = await supabase.from('customers').select('count', { count: 'exact', head: true });
