import { dbService } from '../services/dbService';

interface DashboardProps {
  state: AppState;
  onNavigate: (view: ViewType) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ state, onNavigate }) => {
  const [copied, setCopied] = useState(false);
  const totalRevenue = state.orders.reduce((acc, curr) => acc + curr.total, 0);
  const todayOrders = state.orders.filter(o => 
    new Date(o.orderDate).toDateString() === new Date().toDateString()
  ).length;

  const stats = [
    { label: 'Total Pendapatan', value: `Rp ${totalRevenue.toLocaleString()}`, icon: <DollarSign className="text-emerald-500" />, color: 'bg-emerald-50', link: 'orders' },
    { label: 'Order Hari Ini', value: todayOrders, icon: <ShoppingBag className="text-indigo-500" />, color: 'bg-indigo-50', link: 'orders' },
    { label: 'Total Pelanggan', value: state.customers.length, icon: <Users className="text-blue-500" />, color: 'bg-blue-50', link: 'customers' },
    { label: 'Stok Barang', value: state.products.length, icon: <TrendingUp className="text-amber-500" />, color: 'bg-amber-50', link: 'products' },
  ];

  const sqlSetup = `-- Jalankan SQL ini di Supabase SQL Editor:

create table customers (
  id text primary key,
  name text not null,
  email text,
  address text,
  type text not null
);

create table products (
  id text primary key,
  name text not null,
  description text,
  priceJakarta numeric not null,
  priceLuarKota numeric not null
);

create table orders (
  id text primary key,
  invoiceNumber text not null,
  customerId text references customers(id),
  customerName text not null,
  customerEmail text,
  customerType text not null,
  customerAddress text,
  orderDate timestamp with time zone not null,
  status text not null,
  items jsonb not null,
  subtotal numeric not null,
  downPayment numeric not null,
  payments jsonb not null,
  total numeric not null,
  notes text
);`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(sqlSetup);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link as ViewType)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow cursor-pointer group"
          >
            <div className="flex justify-between items-start">
              <div className={`${stat.color} p-3 rounded-xl`}>
                {stat.icon}
              </div>
              <ArrowUpRight className="text-slate-300 group-hover:text-indigo-500 transition-colors w-4 h-4" />
            </div>
            <div className="mt-4">
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Transaksi Terakhir</h3>
            {state.orders.length > 0 ? (
              <div className="space-y-4">
                {state.orders.slice(0, 5).map((order) => (
                  <div key={order.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl hover:bg-slate-100/80 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-slate-200 shadow-sm">
                        <span className="text-xs font-bold text-indigo-600">INV</span>
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{order.customerName}</p>
                        <p className="text-xs text-slate-400">{order.invoiceNumber}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-bold text-slate-800">Rp {order.total.toLocaleString()}</p>
                      <p className="text-[10px] text-slate-400">{new Date(order.orderDate).toLocaleDateString()}</p>
