import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';
import { supabase } from './lib/supabase';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocalMode, setIsLocalMode] = useState(false);

  // Load Data and Sync Status
  useEffect(() => {
    dbService.setStatusListener((isLocal) => {
      setIsLocalMode(isLocal);
    });

    const loadAllData = async () => {
      setIsLoading(true);
      try {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      } catch (e) {
        console.warn("Falling back to local data due to DB error");
        setIsLocalMode(true);
      } finally {
        setIsLoading(false);
      }
    };
    loadAllData();
  }, []);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  };

  const addCustomer = async (c: Customer) => {
    try {
      await dbService.upsertCustomer(c);
      setState(prev => ({ ...prev, customers: [c, ...prev.customers] }));
    } catch (e) {
      alert("Gagal menyimpan pelanggan");
    }
  };

  const addProduct = async (p: Product) => {
    try {
      await dbService.upsertProduct(p);
      setState(prev => ({ ...prev, products: [p, ...prev.products] }));
    } catch (e) {
      alert("Gagal menyimpan barang");
    }
  };

  const addOrder = async (o: Order) => {
    try {
      await dbService.upsertOrder(o);
      setState(prev => ({ ...prev, orders: [o, ...prev.orders], view: 'orders' }));
    } catch (e) {
      alert("Gagal menyimpan order");
    }
  };

  const updateOrder = async (updated: Order) => {
    try {
      await dbService.upsertOrder(updated);
      setState(prev => ({
        ...prev,
