const LOCAL_STORAGE_KEY = 'orderpro_data_v3';

const getLocalData = () => {
  const data = localStorage.getItem(LOCAL_STORAGE_KEY);
  return data ? JSON.parse(data) : { customers: [], products: [], orders: [] };
};

const saveLocalData = (data: any) => {
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
};

// Helpers to map between DB (snake_case) and App (camelCase)
const mapProductFromDB = (p: any): Product => ({
  id: p.id,
  name: p.name,
  description: p.description,
  priceJakarta: Number(p.price_jakarta || 0),
  priceLuarKota: Number(p.price_luar_kota || 0)
});

const mapProductToDB = (p: Product) => ({
  id: p.id,
  name: p.name,
  description: p.description,
  price_jakarta: p.priceJakarta,
  price_luar_kota: p.priceLuarKota
});

const mapOrderFromDB = (o: any): Order => ({
  id: o.id,
  invoiceNumber: o.invoice_number,
  customerId: o.customer_id,
  customerName: o.customer_name,
  customerEmail: o.customer_email,
  customerType: o.customer_type,
  customerAddress: o.customer_address,
  orderDate: o.order_date,
  status: o.status,
  items: o.items,
  subtotal: Number(o.subtotal || 0),
  downPayment: Number(o.down_payment || 0),
  payments: o.payments || [],
  total: Number(o.total || 0),
  notes: o.notes
});

const mapOrderToDB = (o: Order) => ({
  id: o.id,
  invoice_number: o.invoiceNumber,
  customer_id: o.customerId,
  customer_name: o.customerName,
  customer_email: o.customerEmail,
  customer_type: o.customerType,
  customer_address: o.customer_address,
  order_date: o.orderDate,
  status: o.status,
  items: o.items,
  subtotal: o.subtotal,
  down_payment: o.downPayment,
  payments: o.payments,
  total: o.total,
  notes: o.notes
});

export const dbService = {
  useLocalStorage: false,
  statusListener: null as ((isLocal: boolean) => void) | null,

  setStatusListener(listener: (isLocal: boolean) => void) {
    this.statusListener = listener;
  },

  notifyStatus(isLocal: boolean) {
    this.useLocalStorage = isLocal;
    if (this.statusListener) this.statusListener(isLocal);
  },

  async handleSupabaseError(error: any) {
    const message = error?.message || (typeof error === 'string' ? error : JSON.stringify(error));
    console.error("Supabase Connection Issue:", message);

    // Kode error umum: 42P01 (Tabel tidak ada), PGRST116 (Resource tidak ditemukan), 42703 (Kolom tidak ada)
    const criticalErrorCodes = ['42P01', 'PGRST116', '42703', '42501', 'PT404'];
    if (criticalErrorCodes.includes(error.code) || error.status === 404) {
      this.notifyStatus(true);
    }
    return null; // Return null instead of throwing to avoid crashing the loader
  },

  // Customers
  async getCustomers(): Promise<Customer[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().customers;
    try {
      const { data, error } = await supabase.from('customers').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().customers;
      }
      return data || [];
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().customers;
    }
  },
  async upsertCustomer(customer: Customer) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.customers.findIndex((c: any) => c.id === customer.id);
      if (index > -1) data.customers[index] = customer;
      else data.customers.unshift(customer);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').upsert(customer);
    if (error) await this.handleSupabaseError(error);
  },
  async deleteCustomer(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.customers = data.customers.filter((c: any) => c.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  },

  // Products
  async getProducts(): Promise<Product[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().products;
    try {
      const { data, error } = await supabase.from('products').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().products;
      }
      return (data || []).map(mapProductFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().products;
    }
  },
  async upsertProduct(product: Product) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.products.findIndex((p: any) => p.id === product.id);
      if (index > -1) data.products[index] = product;
      else data.products.unshift(product);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').upsert(mapProductToDB(product));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteProduct(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.products = data.products.filter((p: any) => p.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  },

  // Orders
  async getOrders(): Promise<Order[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().orders;
    try {
      const { data, error } = await supabase.from('orders').select('*').order('order_date', { ascending: false });
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().orders;
      }
      return (data || []).map(mapOrderFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().orders;
    }
  },
  async upsertOrder(order: Order) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.orders.findIndex((o: any) => o.id === order.id);
      if (index > -1) data.orders[index] = order;
      else data.orders.unshift(order);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').upsert(mapOrderToDB(order));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteOrder(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.orders = data.orders.filter((o: any) => o.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  }
};

import React, { useState } from 'react';
import { TrendingUp, Users, ShoppingBag, DollarSign, ArrowUpRight, Database, Terminal, Check, Copy, Smartphone, Monitor, RefreshCw, AlertTriangle } from 'lucide-react';
import { AppState, ViewType } from '../types';

interface DashboardProps {
  state: AppState;
  onNavigate: (view: ViewType) => void;
  isLocalMode: boolean;
}

const Dashboard: React.FC<DashboardProps> = ({ state, onNavigate, isLocalMode }) => {
  const [copied, setCopied] = useState(false);
  const totalRevenue = state.orders.reduce((acc, curr) => acc + curr.total, 0);
  const todayOrders = state.orders.filter(o => 
    new Date(o.orderDate).toDateString() === new Date().toDateString()
  ).length;

  const stats = [
    { label: 'Total Pendapatan', value: `Rp ${totalRevenue.toLocaleString()}`, icon: <DollarSign className="text-emerald-500" />, color: 'bg-emerald-50', link: 'orders' },
    { label: 'Order Hari Ini', value: todayOrders, icon: <ShoppingBag className="text-indigo-500" />, color: 'bg-indigo-50', link: 'orders' },
    { label: 'Total Pelanggan', value: state.customers.length, icon: <Users className="text-blue-500" />, color: 'bg-blue-50', link: 'customers' },
    { label: 'Stok Barang', value: state.products.length, icon: <TrendingUp className="text-amber-500" />, color: 'bg-amber-50', link: 'products' },
  ];

  const sqlSetup = `
-- PENTING: Jika muncul error "column does not exist", hapus tabel lama dulu (opsional):
-- drop table if exists orders;
-- drop table if exists products;
-- drop table if exists customers;

-- 1. Tabel Pelanggan
create table if not exists customers (
  id text primary key,
  name text not null,
  email text,
  address text,
  type text not null
);

-- 2. Tabel Barang
create table if not exists products (
  id text primary key,
  name text not null,
  description text,
  price_jakarta numeric not null,
  price_luar_kota numeric not null
);

-- 3. Tabel Pesanan
create table if not exists orders (
  id text primary key,
  invoice_number text not null,
  customer_id text references customers(id),
  customer_name text not null,
  customer_email text,
  customer_type text not null,
  customer_address text,
  order_date timestamp with time zone not null,
  status text not null,
  items jsonb not null,
  subtotal numeric not null,
  down_payment numeric not null,
  payments jsonb not null,
  total numeric not null,
  notes text
);

-- Matikan RLS agar aplikasi bisa menulis data tanpa Auth
alter table customers disable row level security;
alter table products disable row level security;
alter table orders disable row level security;
  `.trim();

  const copyToClipboard = () => {
    navigator.clipboard.writeText(sqlSetup);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Halo, Admin Toko! 👋</h1>
          <p className="text-slate-500 text-sm">Berikut adalah ringkasan bisnis Anda hari ini.</p>
        </div>
        {isLocalMode && (
           <button 
            onClick={() => window.location.reload()}
            className="flex items-center gap-2 bg-indigo-600 px-5 py-2.5 rounded-xl text-xs font-bold text-white hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
           >
             <RefreshCw size={14} className="animate-spin-slow" />
             Coba Hubungkan Ulang
           </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link as ViewType)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow cursor-pointer group"
          >
            <div className="flex justify-between items-start">
              <div className={`${stat.color} p-3 rounded-xl`}>
                {stat.icon}
              </div>
              <ArrowUpRight className="text-slate-300 group-hover:text-indigo-500 transition-colors w-4 h-4" />
            </div>
            <div className="mt-4">
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {isLocalMode && (
        <div className="bg-amber-50 border border-amber-200 rounded-3xl p-6 md:p-8 shadow-sm">
           <div className="flex items-center gap-3 mb-4 text-amber-700">
             <div className="bg-amber-100 p-2 rounded-lg">
                <AlertTriangle size={24} />
             </div>
             <div>
                <h3 className="text-lg font-bold">Error Koneksi: Database Belum Siap</h3>
                <p className="text-xs font-medium opacity-80">Kami mendeteksi tabel database belum ada atau struktur kolom salah.</p>
             </div>
           </div>

           <div className="bg-white rounded-2xl p-5 border border-amber-200 mb-6 space-y-3">
              <p className="text-sm text-slate-700 font-bold italic">Ikuti langkah ini untuk memperbaiki:</p>
              <ol className="text-xs text-slate-500 space-y-2 list-decimal list-inside">
                <li>Buka <a href="https://supabase.com/dashboard" target="_blank" className="text-indigo-600 font-bold underline">Supabase SQL Editor</a></li>
                <li>Klik tombol <b>"New Query"</b></li>
                <li><b>Tempel (Paste)</b> kode di bawah ini</li>
                <li>Klik tombol <b>RUN</b> (di pojok kanan bawah editor)</li>
                <li>Kembali ke sini dan klik tombol <b>"Coba Hubungkan Ulang"</b> di atas</li>
              </ol>
           </div>

           <div className="relative group">
             <pre className="bg-slate-900 text-slate-300 p-6 rounded-2xl text-[10px] md:text-xs overflow-x-auto font-mono leading-relaxed max-h-80 overflow-y-auto shadow-inner border border-slate-700">
               {sqlSetup}
             </pre>
             <button 
              onClick={copyToClipboard}
              className="absolute top-4 right-4 bg-indigo-600 hover:bg-indigo-700 px-4 py-2 rounded-xl text-white transition-all flex items-center gap-2 text-xs font-bold shadow-lg"
             >
               {copied ? <Check size={14} /> : <Copy size={14} />}
               {copied ? 'Berhasil Salin!' : 'Salin Kode SQL'}
             </button>
           </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Transaksi Terakhir</h3>
            {state.orders.length > 0 ? (
              <div className="space-y-4">
                {state.orders.slice(0, 5).map((order) => (
                  <div key={order.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl hover:bg-slate-100/80 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-slate-200 shadow-sm text-indigo-600">
                        <ShoppingBag size={18} />
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{order.customerName}</p>
                        <p className="text-xs text-slate-400">{order.invoiceNumber}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-bold text-slate-800">Rp {order.total.toLocaleString()}</p>
                      <p className="text-[10px] text-slate-400">{new Date(order.orderDate).toLocaleDateString()}</p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                <ShoppingBag size={48} className="mb-4 opacity-20" />
                <p>Belum ada transaksi</p>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-indigo-900 rounded-3xl p-8 text-white relative overflow-hidden flex flex-col justify-between h-fit shadow-xl shadow-indigo-100">
             <div className="absolute top-0 right-0 p-8 opacity-10">
               <ShoppingBag size={180} />
             </div>
             <div className="relative z-10">
               <h3 className="text-2xl font-bold mb-2">Siap Jualan?</h3>
               <p className="text-indigo-200 text-sm leading-relaxed mb-8">
                 Catat pesanan pelanggan dengan cepat dan kirim invoice profesional hanya dalam beberapa detik.
               </p>
               <button 
                onClick={() => onNavigate('orders')}
                className="bg-white text-indigo-900 px-6 py-3 rounded-xl font-bold text-sm shadow-xl hover:scale-105 transition-transform w-full"
               >
                 Buat Order Baru
               </button>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

