export const dbService = {
  useLocalStorage: false,
  statusListener: null as ((isLocal: boolean) => void) | null,

  setStatusListener(listener: (isLocal: boolean) => void) {
    this.statusListener = listener;
  },

  notifyStatus(isLocal: boolean) {
    this.useLocalStorage = isLocal;
    if (this.statusListener) this.statusListener(isLocal);
  },

  async handleSupabaseError(error: any) {
    const message = error?.message || (typeof error === 'string' ? error : JSON.stringify(error));
    console.error("Supabase Connection Issue:", message);

    // Kode error 42703 = Undefined Column (kolom tidak ditemukan)
    const criticalErrorCodes = ['42P01', 'PGRST116', '42703', '42501', 'PT404'];
    if (criticalErrorCodes.includes(error.code) || error.status === 404) {
      this.notifyStatus(true);
    }
    return null;
  },

  // Customers
  async getCustomers(): Promise<Customer[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().customers;
    try {
      const { data, error } = await supabase.from('customers').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().customers;
      }
      return data || [];
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().customers;
    }
  },
  async upsertCustomer(customer: Customer) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.customers.findIndex((c: any) => c.id === customer.id);
      if (index > -1) data.customers[index] = customer;
      else data.customers.unshift(customer);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').upsert(customer);
    if (error) await this.handleSupabaseError(error);
  },
  async deleteCustomer(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.customers = data.customers.filter((c: any) => c.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  },

  // Products
  async getProducts(): Promise<Product[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().products;
    try {
      const { data, error } = await supabase.from('products').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().products;
      }
      return (data || []).map(mapProductFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().products;
    }
  },
  async upsertProduct(product: Product) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.products.findIndex((p: any) => p.id === product.id);
      if (index > -1) data.products[index] = product;
      else data.products.unshift(product);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').upsert(mapProductToDB(product));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteProduct(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.products = data.products.filter((p: any) => p.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  },

  // Orders
  async getOrders(): Promise<Order[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().orders;
    try {
      // Jika order_date tidak ada, catch block akan menangani error ini
      const { data, error } = await supabase.from('orders').select('*').order('order_date', { ascending: false });
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().orders;
      }
      return (data || []).map(mapOrderFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().orders;
    }
  },
  async upsertOrder(order: Order) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.orders.findIndex((o: any) => o.id === order.id);
      if (index > -1) data.orders[index] = order;
      else data.orders.unshift(order);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').upsert(mapOrderToDB(order));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteOrder(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.orders = data.orders.filter((o: any) => o.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').delete().eq('id', id);
    if (error) await this.handleSupabaseError(error);
  }
};

import React, { useMemo, useState } from 'react';
import { AppState } from '../types';
import { Package, Users, TrendingUp, History, Trophy, Calendar, Search, X, FileText } from 'lucide-react';

interface ReportsProps {
  state: AppState;
}

type TimeRange = 'all' | 'week' | 'month' | 'year';

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const [timeRange, setTimeRange] = useState<TimeRange>('all');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      // 1. Filter Waktu
      const orderDate = new Date(order.orderDate);
      const now = new Date();
      let matchesTime = true;
      if (timeRange === 'week') {
        const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        matchesTime = orderDate >= weekAgo;
      } else if (timeRange === 'month') {
        matchesTime = orderDate.getMonth() === now.getMonth() && orderDate.getFullYear() === now.getFullYear();
      } else if (timeRange === 'year') {
        matchesTime = orderDate.getFullYear() === now.getFullYear();
      }

      // 2. Filter Dropdown (Pelanggan & Produk)
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);

      // 3. Filter Pencarian Teks (Search Term)
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower) ||
        (order.notes && order.notes.toLowerCase().includes(searchLower));

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, timeRange, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + o.subtotal, 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0 || filterCustomer !== 'all')
      .sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, filteredOrders, filterCustomer]);

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20 md:pb-0">

      {/* Search & Filter Bar */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
        {/* Search Bar Utama */}
        <div className="relative group">
          <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-400 group-focus-within:text-indigo-500 transition-colors">
            <Search size={18} />
          </div>
          <input 
            type="text"
            placeholder="Cari nama pelanggan, nomor invoice, atau catatan..."
            className="w-full pl-11 pr-12 py-3.5 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all text-sm font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {searchTerm && (
            <button 
              onClick={() => setSearchTerm('')}
              className="absolute inset-y-0 right-0 pr-4 flex items-center text-slate-400 hover:text-rose-500 transition-colors"
            >
              <X size={18} />
            </button>
          )}
        </div>

        {/* Filter Kategori */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Calendar size={12} className="text-slate-300" /> Periode
            </label>
            <select 
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors appearance-none cursor-pointer"
              value={timeRange}
              onChange={(e) => setTimeRange(e.target.value as TimeRange)}
            >
              <option value="all">Semua Waktu</option>
              <option value="week">7 Hari Terakhir</option>
              <option value="month">Bulan Ini</option>
              <option value="year">Tahun Ini</option>
            </select>
          </div>
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Users size={12} className="text-slate-300" /> Pelanggan
            </label>
            <select 
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors appearance-none cursor-pointer"
              value={filterCustomer}
              onChange={(e) => setFilterCustomer(e.target.value)}
            >
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Package size={12} className="text-slate-300" /> Barang
            </label>
            <select 
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors appearance-none cursor-pointer"
              value={filterProduct}
              onChange={(e) => setFilterProduct(e.target.value)}
            >
              <option value="all">Semua Barang</option>
              {state.products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-indigo-600 rounded-3xl p-8 text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-8 opacity-10">
               <TrendingUp size={120} />
             </div>
             <div className="relative z-10">
               <TrendingUp className="mb-4 opacity-50" size={24} />
               <p className="text-indigo-100 text-[10px] font-black uppercase tracking-widest">Total Penjualan Terfilter</p>
               <h3 className="text-3xl font-black mt-2">
                 Rp {filteredOrders.reduce((sum, o) => sum + o.subtotal, 0).toLocaleString()}
               </h3>
               <p className="text-[10px] text-indigo-200 mt-2 font-medium">Dari {filteredOrders.length} transaksi</p>
             </div>
          </div>

          <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
             <div className="flex items-center gap-3 mb-6">
                <div className="bg-amber-50 p-2 rounded-xl text-amber-500">
                  <Trophy size={18} />
                </div>
                <h4 className="font-bold text-slate-800 text-sm">Produk Terlaris</h4>
             </div>
             <div className="space-y-4">
               {productSales.slice(0, 5).map((p, i) => (
                 <div key={i} className="flex items-center justify-between group">
                   <div className="min-w-0 flex-1">
                     <p className="text-xs font-bold text-slate-700 truncate group-hover:text-indigo-600 transition-colors">{p.name}</p>
                     <div className="w-full bg-slate-50 h-1 mt-2 rounded-full overflow-hidden">
                        <div 
                          className="bg-indigo-400 h-full rounded-full transition-all duration-1000" 
                          style={{ width: `${Math.min(100, (p.qty / (productSales[0]?.qty || 1)) * 100)}%` }}
                        />
                     </div>
                   </div>
                   <span className="ml-4 text-[10px] font-black text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-lg shrink-0">{p.qty}x</span>
                 </div>
               ))}
               {productSales.length === 0 && (
                 <div className="text-center py-8">
                   <Package className="mx-auto text-slate-100 mb-2" size={32} />
                   <p className="text-slate-400 text-[10px] italic">Tidak ada data produk</p>
                 </div>
               )}
             </div>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="flex items-center justify-between">
             <div className="flex items-center gap-3">
                <div className="bg-indigo-50 p-2 rounded-xl text-indigo-600">
                  <FileText size={18} />
                </div>
                <h4 className="font-bold text-slate-800 text-md">Detail Riwayat Filter</h4>
             </div>
             <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-3 py-1 rounded-full uppercase">
               {customerReports.length} Entitas
             </span>
          </div>
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden overflow-x-auto">
             <table className="w-full text-left min-w-[450px]">
                <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Pelanggan</th>
                    <th className="px-6 py-4 text-center">Frekuensi</th>
                    <th className="px-6 py-4 text-right">Nilai Belanja</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {customerReports.map((c, i) => (
                    <tr key={i} className="hover:bg-slate-50/80 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-500 transition-colors">
                            {c.name.substring(0,2).toUpperCase()}
                          </div>
                          <span className="text-xs font-bold text-slate-800">{c.name}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-2.5 py-1 rounded-lg">
                          {c.orderCount} Order
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-xs font-black text-slate-800">Rp {c.totalSpent.toLocaleString()}</span>
                      </td>
                    </tr>
                  ))}
                  {customerReports.length === 0 && (
                    <tr>
                      <td colSpan={3} className="px-6 py-16 text-center">
                        <Search className="mx-auto text-slate-100 mb-3" size={48} />
                        <p className="text-slate-400 text-sm font-medium">Data tidak ditemukan untuk kriteria ini</p>
                        <button 
                          onClick={() => {setSearchTerm(''); setFilterCustomer('all'); setFilterProduct('all'); setTimeRange('all');}}
                          className="mt-4 text-indigo-600 text-xs font-bold hover:underline"
                        >
                          Reset Semua Filter
                        </button>
                      </td>
                    </tr>
                  )}
                </tbody>
             </table>
          </div>
        </div>
      </div>
    </div>
  );
};

