             <h2 className="text-lg font-semibold text-slate-800 capitalize">
               {state.view.replace('_', ' ')}
             </h2>
             {isLocalMode && (
               <div className="flex items-center gap-2 px-3 py-1 bg-amber-50 text-amber-600 rounded-full border border-amber-100 text-[11px] font-bold">
                 <AlertCircle size={14} />
                 Penyimpanan Lokal (Database Cloud Belum Setup)
               </div>
             )}
           </div>
           <div className="text-sm text-slate-400 flex items-center gap-2">
             <CalendarIcon size={14} />
             {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
           </div>
        </header>

        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {state.view === 'dashboard' && (
            <Dashboard state={state} onNavigate={setView} isLocalMode={isLocalMode} />
          )}

          {state.view === 'customers' && (
            <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />
          )}

          {state.view === 'products' && (
            <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />
          )}

          {state.view === 'orders' && (
            <OrderManager 
              state={state} 
              onAddOrder={addOrder}
              onUpdateOrder={updateOrder}
              onDeleteOrder={deleteOrder} 
              onViewInvoice={viewInvoice}
            />
          )}

          {state.view === 'reports' && (
            <Reports state={state} />
          )}

          {state.view === 'invoice_detail' && state.activeOrder && (
            <div className="animate-in fade-in duration-300">
               <button 
                onClick={() => setView('orders')}
                className="flex items-center gap-2 text-slate-500 hover:text-slate-800 mb-6 transition-colors font-medium text-sm"
              >
                ← Kembali ke Order
              </button>
              <InvoiceView order={state.activeOrder} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

