import React, { useRef, useState, useEffect } from 'react';
import { Download, Printer, Share2, Sparkles, Image as ImageIcon, FileText, CheckCircle2 } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const fetchSummary = async () => {
      setIsAiLoading(true);
      const summary = await getSmartOrderSummary(order);
      setAiSummary(summary);
      setIsAiLoading(false);
    };
    fetchSummary();
  }, [order]);

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${order.invoiceNumber}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2, useCORS: true });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${order.invoiceNumber}.pdf`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pb-12">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold text-slate-800">Preview Nota</h3>
            <div className="flex gap-2">
                <button 
                  onClick={handleDownloadJPG}
                  className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 flex items-center gap-2 text-xs font-bold transition-all shadow-sm"
                >
                  <ImageIcon className="w-4 h-4" />
                  Download JPG
                </button>
                <button 
                  onClick={handleDownloadPDF}
                  className="px-4 py-2 bg-indigo-600 text-white border border-indigo-600 rounded-xl hover:bg-indigo-700 flex items-center gap-2 text-xs font-bold transition-all shadow-lg shadow-indigo-200"
                >
                  <FileText className="w-4 h-4" />
                  Export PDF
                </button>
            </div>
        </div>

        <div 
          ref={invoiceRef}
          className="bg-white rounded-lg shadow-2xl p-10 md:p-16 text-slate-800 border border-slate-100 overflow-hidden"
          style={{ width: '100%', maxWidth: '800px', margin: '0 auto' }}
        >
          {/* Header */}
          <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-12">
            <div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tighter">NOTA</h1>
              <p className="text-slate-400 mt-2 font-bold tracking-widest uppercase text-xs">NO. {order.invoiceNumber}</p>
            </div>
            <div className="text-right">
                <p className="text-xs font-bold text-slate-300 uppercase">Tanggal</p>
                <p className="font-bold text-slate-800">{new Date(order.orderDate).toLocaleDateString('id-ID', { dateStyle: 'long' })}</p>
            </div>
          </div>

          {/* Billing Info */}
          <div className="mb-16">
            <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-4">Kepada</h4>
            <p className="text-xl font-bold text-slate-900">{order.customerName}</p>
            {order.customerAddress && (
              <div className="text-sm text-slate-500 mt-2 leading-relaxed whitespace-pre-wrap max-w-sm">
                {order.customerAddress}
              </div>
            )}
          </div>

          {/* Table */}
          <table className="w-full mb-12">
            <thead>
              <tr className="border-b border-slate-200 text-left">
                <th className="py-4 text-xs font-black text-slate-900 uppercase tracking-widest">Nama Barang</th>
                <th className="py-4 px-4 text-xs font-black text-slate-900 uppercase tracking-widest text-center">Qty</th>
                <th className="py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Harga</th>
                <th className="py-4 text-xs font-black text-slate-900 uppercase tracking-widest text-right">Subtotal</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {order.items.map((item) => (
                <tr key={item.id}>
                  <td className="py-5 pr-4 text-sm font-bold text-slate-800">
                    {item.name}
                  </td>
                  <td className="py-5 px-4 text-sm text-center text-slate-600 font-medium">{item.quantity}</td>
                  <td className="py-5 text-sm text-right text-slate-600 font-medium">Rp {item.unitPrice.toLocaleString()}</td>
                  <td className="py-5 text-sm text-right font-bold text-slate-900">Rp {(item.quantity * item.unitPrice).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* Totals */}
          <div className="flex justify-end">
