import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, TrendingUp, Trophy, 
  Calendar, Search, X, FileText, Download, Image as ImageIcon 
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      // 1. Filter Waktu Berdasarkan Rentang Tanggal
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      // 2. Filter Dropdown (Pelanggan & Produk)
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);

      // 3. Filter Pencarian Teks
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower) ||
        (order.notes && order.notes.toLowerCase().includes(searchLower));

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + o.subtotal, 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0 || filterCustomer !== 'all')
      .sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, filteredOrders, filterCustomer]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f9fafb' });
    const link = document.createElement('a');
    link.download = `Laporan_Order_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f9fafb' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_Order_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20 md:pb-0">

      {/* Search & Filter Bar */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <h3 className="font-bold text-slate-800 text-lg">Filter Laporan</h3>
           <div className="flex gap-2 w-full md:w-auto">
              <button 
                onClick={handleDownloadJPG}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 text-[11px] font-black uppercase tracking-wider transition-all"
              >
                <ImageIcon size={14} /> JPG
              </button>
              <button 
                onClick={handleDownloadPDF}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 text-[11px] font-black uppercase tracking-wider transition-all shadow-lg shadow-indigo-100"
              >
                <FileText size={14} /> PDF
              </button>
           </div>
        </div>

        {/* Search Bar */}
        <div className="relative group">
          <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-slate-400 group-focus-within:text-indigo-500 transition-colors">
            <Search size={18} />
          </div>
          <input 
            type="text"
            placeholder="Cari nama pelanggan, nomor invoice..."
            className="w-full pl-11 pr-12 py-3 rounded-2xl bg-slate-50 border border-slate-100 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all text-sm font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {searchTerm && (
            <button onClick={() => setSearchTerm('')} className="absolute inset-y-0 right-0 pr-4 flex items-center text-slate-400 hover:text-rose-500 transition-colors">
              <X size={18} />
            </button>
          )}
        </div>

        {/* Filter Baris 2 */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Calendar size={12} className="text-slate-300" /> Dari Tanggal
            </label>
            <input 
              type="date"
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors cursor-pointer"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Calendar size={12} className="text-slate-300" /> Sampai Tanggal
            </label>
            <input 
              type="date"
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors cursor-pointer"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Users size={12} className="text-slate-300" /> Pelanggan
            </label>
            <select 
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors appearance-none cursor-pointer"
              value={filterCustomer}
              onChange={(e) => setFilterCustomer(e.target.value)}
            >
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 ml-1">
              <Package size={12} className="text-slate-300" /> Barang
            </label>
            <select 
              className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:border-indigo-300 transition-colors appearance-none cursor-pointer"
              value={filterProduct}
              onChange={(e) => setFilterProduct(e.target.value)}
            >
              <option value="all">Semua Barang</option>
              {state.products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
        </div>
      </div>

      {/* Konten Laporan yang bisa diunduh */}
      <div ref={reportRef} className="space-y-8 p-4 md:p-0">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">
          <div className="lg:col-span-1 space-y-6">
            {/* Kartu Ringkasan */}
            <div className="bg-indigo-600 rounded-3xl p-8 text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
               <div className="absolute top-0 right-0 p-8 opacity-10">
                 <TrendingUp size={120} />
               </div>
               <div className="relative z-10">
                 <TrendingUp className="mb-4 opacity-50" size={24} />
                 <p className="text-indigo-100 text-[10px] font-black uppercase tracking-widest">Total Penjualan Terfilter</p>
                 <h3 className="text-3xl font-black mt-2">
                   Rp {filteredOrders.reduce((sum, o) => sum + o.subtotal, 0).toLocaleString()}
                 </h3>
                 <p className="text-[10px] text-indigo-200 mt-2 font-medium">Dari {filteredOrders.length} transaksi</p>
                 { (startDate || endDate) && (
                   <p className="text-[9px] mt-4 font-bold bg-indigo-500/30 px-3 py-1 rounded-full inline-block">
                     Periode: {startDate || '?'} s/d {endDate || '?'}
                   </p>
                 )}
               </div>
            </div>

            {/* Produk Terlaris */}
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
               <div className="flex items-center gap-3 mb-6">
                  <div className="bg-amber-50 p-2 rounded-xl text-amber-500">
                    <Trophy size={18} />
                  </div>
                  <h4 className="font-bold text-slate-800 text-sm">Produk Terlaris</h4>
               </div>
               <div className="space-y-4">
                 {productSales.slice(0, 5).map((p, i) => (
                   <div key={i} className="flex items-center justify-between group">
                     <div className="min-w-0 flex-1">
                       <p className="text-xs font-bold text-slate-700 truncate group-hover:text-indigo-600 transition-colors">{p.name}</p>
                       <div className="w-full bg-slate-50 h-1 mt-2 rounded-full overflow-hidden">
