import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, Calendar as CalendarIcon, Database, AlertCircle
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocalMode, setIsLocalMode] = useState(false);

  useEffect(() => {
    dbService.setStatusListener((isLocal) => {
      setIsLocalMode(isLocal);
    });

    const loadAllData = async () => {
      setIsLoading(true);
      try {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      } catch (e) {
        setIsLocalMode(true);
      } finally {
        setIsLoading(false);
      }
    };
    loadAllData();
  }, []);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  };

  const addCustomer = async (c: Customer) => {
    try {
      await dbService.upsertCustomer(c);
      setState(prev => ({ ...prev, customers: [c, ...prev.customers] }));
    } catch (e) {
      alert("Gagal menyimpan pelanggan");
    }
  };

  const updateCustomer = async (c: Customer) => {
    try {
      await dbService.upsertCustomer(c);
      // Sinkronisasi ke order yang sudah ada
      const updatedOrders = state.orders.map(order => {
        if (order.customerId === c.id) {
          return {
            ...order,
            customerName: c.name,
            customerAddress: c.address,
            customerEmail: c.email,
            customerType: c.type
          };
        }
        return order;
      });

      // Update di database juga untuk persistensi
      for (const order of updatedOrders.filter(o => o.customerId === c.id)) {
        await dbService.upsertOrder(order);
      }

      setState(prev => ({
        ...prev,
        customers: prev.customers.map(item => item.id === c.id ? c : item),
        orders: updatedOrders
      }));
    } catch (e) {
      alert("Gagal memperbarui pelanggan");
    }
  };

  const addProduct = async (p: Product) => {
    try {
      await dbService.upsertProduct(p);
      setState(prev => ({ ...prev, products: [p, ...prev.products] }));
    } catch (e) {
      alert("Gagal menyimpan barang");
    }
  };

  const updateProduct = async (p: Product) => {
    try {
      await dbService.upsertProduct(p);
      // Sinkronisasi harga dan nama di order yang sudah ada
      const updatedOrders = state.orders.map(order => {
        const hasProduct = order.items.some(i => i.productId === p.id);
        if (hasProduct) {
          const updatedItems = order.items.map(item => {
            if (item.productId === p.id) {
              const newPrice = order.customerType === 'Luar Kota' ? p.priceLuarKota : p.priceJakarta;
              return { ...item, name: p.name, unitPrice: newPrice };
            }
            return item;
          });
          const newSubtotal = updatedItems.reduce((sum, i) => sum + (i.quantity * i.unitPrice), 0);
          return { 
            ...order, 
            items: updatedItems, 
            subtotal: newSubtotal,
            total: newSubtotal - order.downPayment 
          };
        }
        return order;
      });

      for (const order of updatedOrders.filter(o => o.items.some(i => i.productId === p.id))) {
        await dbService.upsertOrder(order);
      }

      setState(prev => ({
        ...prev,
        products: prev.products.map(item => item.id === p.id ? p : item),
        orders: updatedOrders
      }));
    } catch (e) {
      alert("Gagal memperbarui barang");
    }
  };

  const addOrder = async (o: Order) => {
    try {
      await dbService.upsertOrder(o);
      setState(prev => ({ ...prev, orders: [o, ...prev.orders], view: 'orders' }));
    } catch (e) {
      alert("Gagal menyimpan order");
    }
  };

  const updateOrder = async (updated: Order) => {
    try {
      await dbService.upsertOrder(updated);
      setState(prev => ({
        ...prev,
        orders: prev.orders.map(o => o.id === updated.id ? updated : o)
      }));
    } catch (e) {
      alert("Gagal memperbarui order");
    }
  };

  const deleteCustomer = async (id: string) => {
    try {
      await dbService.deleteCustomer(id);
      setState(prev => ({ ...prev, customers: prev.customers.filter(c => c.id !== id) }));
    } catch (e) {
      alert("Gagal menghapus pelanggan");
    }
  };

  const deleteProduct = async (id: string) => {
    try {
      await dbService.deleteProduct(id);
      setState(prev => ({ ...prev, products: prev.products.filter(p => p.id !== id) }));
    } catch (e) {
      alert("Gagal menghapus barang");
    }
  };

  const deleteOrder = async (id: string) => {
    try {
      await dbService.deleteOrder(id);
      setState(prev => ({ ...prev, orders: prev.orders.filter(o => o.id !== id) }));
    } catch (e) {
      alert("Gagal menghapus order");
    }
  };

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
      <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-slate-500 font-medium animate-pulse">Memuat Data...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <header className="md:hidden bg-slate-900 text-white p-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg">
            <Package size={20} />
          </div>
          <span className="font-bold tracking-tight">OrderPro AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 hover:bg-slate-800 rounded-lg">
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}

      <aside className={`w-64 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen`}>
        <div className="p-6 hidden md:flex items-center gap-3 border-b border-slate-800">
          <div className="bg-indigo-600 p-2 rounded-lg"><Package className="text-white w-6 h-6" /></div>
          <span className="text-xl font-bold text-white">OrderPro AI</span>
        </div>
        <nav className="flex-1 p-4 space-y-2 mt-4">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Master Data</div>
          <NavItem icon={<Users size={20} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={20} />} label="Barang" active={state.view === 'products'} onClick={() => setView('products')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Transaksi</div>
          <NavItem icon={<ShoppingCart size={20} />} label="Order Masuk" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={20} />} label="Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />
        </nav>
      </aside>

      <main className="flex-1 overflow-y-auto">
        <header className="hidden md:flex bg-white border-b h-16 items-center px-8 sticky top-0 z-30 justify-between">
           <h2 className="text-lg font-semibold text-slate-800 capitalize">{state.view.replace('_', ' ')}</h2>
           <div className="text-sm text-slate-400 flex items-center gap-2">
             <CalendarIcon size={14} /> {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
           </div>
        </header>

        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} isLocalMode={isLocalMode} />}
          {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
          {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
          {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
          {state.view === 'reports' && <Reports state={state} />}
          {state.view === 'invoice_detail' && state.activeOrder && (
            <div className="animate-in fade-in duration-300">
               <button onClick={() => setView('orders')} className="flex items-center gap-2 text-slate-500 hover:text-slate-800 mb-6 font-medium text-sm">← Kembali</button>
              <InvoiceView order={state.activeOrder} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl font-medium text-sm ${active ? 'bg-indigo-600 text-white' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    {icon}<span>{label}</span>
  </button>
);

export default App;

