import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, User, 
  Package, Check, CreditCard, Edit3, X
} from 'lucide-react';
import { AppState, Order, OrderItem, Product, OrderStatus, LocationType, PaymentRecord } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => void;
  onUpdateOrder: (o: Order) => void;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onUpdateOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);

  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);

  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId);
      setOrderItems(editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })));
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setIsFormOpen(true);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? product.priceLuarKota : product.priceJakarta;
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * item.qty);
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + p.amount, 0);
  }, [payments]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || orderItems.length === 0) return;

    const items: OrderItem[] = orderItems.map(oi => {
      const p = state.products.find(product => product.id === oi.productId)!;
      return {
        id: Math.random().toString(36).substr(2, 9),
        productId: p.id,
        name: p.name,
        quantity: oi.qty,
        unitPrice: calculateItemPrice(p, selectedCustomer.type)
      };
    });

    const orderData: Order = {
      id: editingOrder ? editingOrder.id : Math.random().toString(36).substr(2, 9),
      invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
      customerId: selectedCustomer.id,
      customerName: selectedCustomer.name,
      customerEmail: selectedCustomer.email,
      customerType: selectedCustomer.type,
      customerAddress: selectedCustomer.address,
      orderDate: editingOrder ? editingOrder.orderDate : new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: calculatedSubtotal,
      downPayment: currentTotalPaid,
      payments,
      total: calculatedSubtotal - currentTotalPaid,
      notes
    };

    if (editingOrder) {
      onUpdateOrder(orderData);
    } else {
      onAddOrder(orderData);
    }
    resetForm();
  };

  const addPayment = () => {
    if (newPaymentAmount <= 0) return;
    const newRecord: PaymentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      amount: newPaymentAmount,
      date: new Date().toISOString(),
      note: newPaymentNote || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
    };
    setPayments([...payments, newRecord]);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setShowPaymentInput(false);
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Hapus pesanan ini secara permanen? Data tidak dapat dikembalikan.')) {
      onDeleteOrder(id);
    }
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-slate-800">Order Masuk</h2>
          <p className="text-slate-500 text-xs md:text-sm">Gunakan data Master Pelanggan & Barang</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="w-full sm:w-auto bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100"
        >
          <Plus size={18} />
          Order Baru
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-100 p-4 md:p-8 animate-in slide-in-from-top-4 duration-300">
           <div className="flex justify-between items-center mb-6">
             <h3 className="text-lg md:text-xl font-black text-slate-900">{editingOrder ? 'Edit Pesanan' : 'Pesanan Baru'}</h3>
             <button onClick={resetForm} className="p-2 hover:bg-slate-50 rounded-full text-slate-400"><X size={20}/></button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-6 md:space-y-8">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
                {/* Customer Select */}
                <div className="space-y-4">
                  <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <User size={14} /> 1. Pilih Pelanggan
                  </h3>
                  <select 
                    required
                    disabled={!!editingOrder}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-medium disabled:opacity-50 text-sm"
                    value={selectedCustomerId}
                    onChange={e => setSelectedCustomerId(e.target.value)}
                  >
                    <option value="">-- Cari Pelanggan --</option>
                    {state.customers.map(c => (
                      <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                    ))}
                  </select>
                </div>

