import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, TrendingUp, Trophy, 
  Calendar, Search, FileText, Image as ImageIcon, Clock 
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();

    if (type === 'today') {
      // Hari ini
    } else if (type === 'week') {
      start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
      start.setMonth(end.getMonth() - 1);
    } else if (type === 'year') {
      start.setFullYear(end.getFullYear() - 1);
    }

    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower);

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + o.subtotal, 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0 || filterCustomer !== 'all')
      .sort((a, b) => b.orderCount - a.orderCount);
  }, [state.customers, filteredOrders, filterCustomer]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f9fafb' });
    const link = document.createElement('a');
    link.download = `Laporan_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f9fafb' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 md:space-y-8 pb-20">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between gap-4">
           <div>
             <h3 className="font-bold text-slate-800 text-lg">Analisis Bisnis</h3>
             <p className="text-slate-400 text-xs">Pantau performa penjualan secara real-time</p>
           </div>
           <div className="flex gap-2">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 text-[10px] font-black transition-all hover:bg-slate-50"><ImageIcon size={14} /> JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black transition-all shadow-lg shadow-indigo-100 hover:bg-indigo-700"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="flex flex-wrap gap-2 pt-2">
           <span className="text-[10px] font-black text-slate-300 uppercase flex items-center gap-1 mr-2"><Clock size={12}/> Preset Filter:</span>
           <button onClick={() => setPreset('today')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Hari Ini</button>
           <button onClick={() => setPreset('week')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Mingguan</button>
           <button onClick={() => setPreset('month')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Bulanan</button>
           <button onClick={() => setPreset('year')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Tahunan</button>
           <button onClick={() => {setStartDate(''); setEndDate('');}} className="px-3 py-1.5 bg-rose-50 text-rose-500 rounded-lg text-[10px] font-bold hover:bg-rose-100 transition-colors">Clear</button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dari Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sampai Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pelanggan</label>
            <select className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none" value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian</label>
            <div className="relative">
              <input type="text" placeholder="Cari invoice..." className="w-full pl-8 pr-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-3 text-slate-300" size={14} />
            </div>
          </div>
        </div>
      </div>

      <div ref={reportRef} className="space-y-8 p-4 md:p-0">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-indigo-600 rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
               <TrendingUp className="mb-4 opacity-50" size={24} />
               <p className="text-indigo-100 text-[10px] font-black uppercase tracking-widest">Total Penjualan</p>
               <h3 className="text-3xl font-black mt-2">Rp {filteredOrders.reduce((sum, o) => sum + o.subtotal, 0).toLocaleString()}</h3>
               <p className="text-[10px] text-indigo-200 mt-2">{filteredOrders.length} transaksi dalam periode ini</p>
            </div>

            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
               <div className="flex items-center gap-3 mb-6"><Trophy size={18} className="text-amber-500" /><h4 className="font-bold text-slate-800 text-sm">Produk Terlaris</h4></div>
               <div className="space-y-4">
                 {productSales.slice(0, 5).map((p, i) => (
                   <div key={i} className="flex items-center justify-between">
                     <p className="text-xs font-bold text-slate-700 truncate flex-1">{p.name}</p>
                     <span className="ml-4 text-[10px] font-black text-indigo-600 bg-indigo-50 px-2.5 py-1 rounded-lg">{p.qty}x</span>
                   </div>
                 ))}
               </div>
            </div>
          </div>

          <div className="lg:col-span-2">
            <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <tr>
                      <th className="px-6 py-4">Pelanggan</th>
                      <th className="px-6 py-4 text-center">Frekuensi</th>
                      <th className="px-6 py-4 text-right">Nilai Belanja</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {customerReports.map((c, i) => (
                      <tr key={i} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 flex items-center gap-3">
                            <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400">{c.name.substring(0,2).toUpperCase()}</div>
                            <span className="text-xs font-bold text-slate-800">{c.name}</span>
                        </td>
                        <td className="px-6 py-4 text-center"><span className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-2.5 py-1 rounded-lg">{c.orderCount}x</span></td>
                        <td className="px-6 py-4 text-right"><span className="text-xs font-black text-slate-800">Rp {c.totalSpent.toLocaleString()}</span></td>
                      </tr>
                    ))}
                    {customerReports.length === 0 && (
                      <tr>
                        <td colSpan={3} className="px-6 py-12 text-center text-slate-400 text-xs italic">Tidak ada data ditemukan</td>
