  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);

  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId);
      setOrderItems(editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })));
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setIsFormOpen(true);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? product.priceLuarKota : product.priceJakarta;
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * item.qty);
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + p.amount, 0);
  }, [payments]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomer || orderItems.length === 0) return;

    const items: OrderItem[] = orderItems.map(oi => {
      const p = state.products.find(product => product.id === oi.productId)!;
      return {
        id: Math.random().toString(36).substr(2, 9),
        productId: p.id,
        name: p.name,
        quantity: oi.qty,
        unitPrice: calculateItemPrice(p, selectedCustomer.type)
      };
    });

    const orderData: Order = {
      id: editingOrder ? editingOrder.id : Math.random().toString(36).substr(2, 9),
      invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
      customerId: selectedCustomer.id,
      customerName: selectedCustomer.name,
      customerEmail: selectedCustomer.email,
      customerType: selectedCustomer.type,
      customerAddress: selectedCustomer.address,
      orderDate: editingOrder ? editingOrder.orderDate : new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: calculatedSubtotal,
      downPayment: currentTotalPaid,
      payments,
      total: calculatedSubtotal - currentTotalPaid,
      notes
    };

    if (editingOrder) {
      onUpdateOrder(orderData);
    } else {
      onAddOrder(orderData);
    }
    resetForm();
  };

  const addPayment = () => {
    if (newPaymentAmount <= 0) return;
    const newRecord: PaymentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      amount: newPaymentAmount,
      date: new Date().toISOString(),
      note: newPaymentNote || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
    };
    setPayments([...payments, newRecord]);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setShowPaymentInput(false);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-slate-800">Order Masuk</h2>
          <p className="text-slate-500 text-xs md:text-sm font-medium">Gunakan data Master Pelanggan & Barang</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="w-full sm:w-auto bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={18} />
          Order Baru
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-3xl shadow-2xl border border-slate-100 p-6 md:p-8 animate-in slide-in-from-top-4 duration-500">
           <div className="flex justify-between items-center mb-8">
             <h3 className="text-lg md:text-xl font-black text-slate-900 tracking-tight">{editingOrder ? 'Edit Pesanan' : 'Buat Pesanan Baru'}</h3>
             <button onClick={resetForm} className="p-2 hover:bg-slate-50 rounded-full text-slate-400 transition-colors"><X size={20}/></button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-8">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="space-y-4">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <User size={14} className="text-indigo-500"/> 1. Pilih Pelanggan
                  </h3>
                  <select 
                    required
                    disabled={!!editingOrder}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-bold disabled:opacity-50 text-sm appearance-none cursor-pointer"
                    value={selectedCustomerId}
                    onChange={e => setSelectedCustomerId(e.target.value)}
                  >
                    <option value="">-- Cari Pelanggan --</option>
                    {state.customers.map(c => (
                      <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-4">
                   <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <Package size={14} className="text-indigo-500"/> 2. Kelola Barang
                  </h3>
                  <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 no-scrollbar">
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                          existing ? 'bg-indigo-50 border-indigo-200 shadow-sm' : 'bg-slate-50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-4">
                             <p className="text-xs md:text-sm font-black text-slate-800 truncate">{p.name}</p>
                             <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">
                               Rp {(selectedCustomer?.type === LocationType.LUAR_KOTA ? p.priceLuarKota : p.priceJakarta).toLocaleString()}
                             </p>
                           </div>
                           <div className="flex items-center gap-3 shrink-0">
                             {existing && (
                               <input 
                                 type="number"
                                 min="1"
                                 className="w-12 px-1 py-1.5 rounded-lg border border-indigo-200 text-xs font-black text-center outline-none bg-white text-indigo-700"
                                 value={existing.qty}
                                 onChange={e => {
                                   const val = parseInt(e.target.value) || 1;
                                   setOrderItems(orderItems.map(i => i.productId === p.id ? { ...i, qty: val } : i));
                                 }}
                               />
                             )}
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-9 h-9 rounded-xl flex items-center justify-center transition-all shadow-sm ${
                                 existing ? 'bg-indigo-600 text-white' : 'bg-white text-slate-300 border border-slate-200 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={18} /> : <Plus size={18} />}
                             </button>
                           </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <CreditCard size={14} className="text-indigo-500"/> 3. Rincian Pembayaran
                    </h3>
                    <button 
                      type="button" 
                      onClick={() => setShowPaymentInput(!showPaymentInput)}
                      className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-lg border border-indigo-100 hover:bg-indigo-100 transition-all"
                    >
                      {showPaymentInput ? 'Tutup Input' : '+ Tambah DP'}
                    </button>
                  </div>

                  {showPaymentInput && (
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 space-y-3 shadow-inner animate-in fade-in zoom-in-95 duration-200">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <div className="relative">
                           <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-[10px] font-black">RP</span>
                           <input 
                            type="number"
                            placeholder="Jumlah"
                            className="w-full pl-9 pr-4 py-2 rounded-xl border border-slate-200 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500"
                            value={newPaymentAmount || ''}
                            onChange={e => setNewPaymentAmount(Number(e.target.value))}
                          />
                        </div>
                        <input 
                          type="text"
                          placeholder="Keterangan (e.g. DP 1)"
                          className="px-4 py-2 rounded-xl border border-slate-200 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500"
                          value={newPaymentNote}
                          onChange={e => setNewPaymentNote(e.target.value)}
                        />
                      </div>
                      <button 
                        type="button" 
                        onClick={addPayment}
                        className="w-full bg-slate-900 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all"
                      >
                        Konfirmasi Pembayaran
                      </button>
                    </div>
                  )}

                  <div className="space-y-2">
                    {payments.map((p) => (
                      <div key={p.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                        <div className="flex items-center gap-4">
                          <div className="w-8 h-8 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600 shadow-sm">
                            <Check size={14}/>
                          </div>
                          <div>
                            <p className="text-xs font-black text-slate-800">{p.note}</p>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{new Date(p.date).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <p className="text-sm font-black text-slate-800">Rp {p.amount.toLocaleString()}</p>
                      </div>
                    ))}
                    {payments.length === 0 && <p className="text-center py-4 text-[10px] text-slate-300 font-bold uppercase tracking-widest italic border border-dashed rounded-2xl">Belum ada pembayaran.</p>}
                  </div>
                </div>

                <div className="space-y-2">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Catatan Invoice</h3>
                  <textarea 
                    className="w-full px-5 py-4 rounded-3xl border border-slate-200 bg-slate-50 outline-none text-sm font-medium h-32 md:h-40 focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner"
                    placeholder="Tulis instruksi tambahan jika ada..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
             </div>

             <div className="flex flex-col md:flex-row md:items-center justify-between bg-slate-900 p-6 md:p-8 rounded-[2rem] text-white gap-6 shadow-2xl shadow-indigo-100">
               <div>
                  <p className="text-slate-400 text-[10px] mb-2 font-black uppercase tracking-[0.2em]">Total Pesanan: Rp {calculatedSubtotal.toLocaleString()}</p>
                  <h4 className="text-2xl md:text-4xl font-black tracking-tighter">
                    Sisa Tagihan: <span className="text-indigo-400">Rp {(calculatedSubtotal - currentTotalPaid).toLocaleString()}</span>
                  </h4>
               </div>
               <button 
                type="submit"
                disabled={!selectedCustomerId || orderItems.length === 0}
                className="w-full md:w-auto bg-indigo-600 hover:bg-indigo-700 disabled:opacity-30 disabled:cursor-not-allowed text-white px-10 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-xl shadow-indigo-500/20 active:scale-95"
               >
                 {editingOrder ? 'Simpan Perubahan' : 'Finalisasi & Lihat Nota'}
               </button>
             </div>
           </form>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden overflow-x-auto transition-all hover:shadow-md">
        <table className="w-full text-left min-w-[700px]">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
            <tr>
              <th className="px-6 py-5">No. Invoice</th>
              <th className="px-6 py-5">Pelanggan</th>
              <th className="px-6 py-5 text-right">Subtotal</th>
              <th className="px-6 py-5 text-right">Sisa Bayar</th>
              <th className="px-6 py-5 text-center">Opsi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {state.orders.map(o => (
              <tr key={o.id} className="hover:bg-slate-50 transition-all group">
                <td className="px-6 py-5">
                  <p className="text-sm font-black text-slate-800">{o.invoiceNumber}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{new Date(o.orderDate).toLocaleDateString('id-ID', { dateStyle: 'medium' })}</p>
                </td>
                <td className="px-6 py-5">
                  <p className="text-sm font-bold text-slate-700 truncate max-w-[150px]">{o.customerName}</p>
                  <span className="inline-flex px-1.5 py-0.5 rounded-lg bg-indigo-50 text-indigo-500 text-[8px] font-black uppercase tracking-wider">
                    {o.customerType}
                  </span>
                </td>
                <td className="px-6 py-5 text-right text-sm font-bold text-slate-600">
                  Rp {o.subtotal.toLocaleString()}
                </td>
                <td className="px-6 py-5 text-right">
                  <div className={`text-sm font-black ${o.total <= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                    Rp {o.total.toLocaleString()}
                    {o.total <= 0 && <span className="ml-1 text-[8px] uppercase tracking-widest opacity-60">Lunas</span>}
                  </div>
                </td>
                <td className="px-6 py-5">
                  <div className="flex justify-center gap-2">
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onViewInvoice(o); }}
                      className="p-2 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                    >
                      <Eye size={18} />
                    </button>
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setEditingOrder(o); }}
                      className="p-2 text-slate-300 hover:text-amber-500 hover:bg-amber-50 rounded-xl transition-all"
                    >
                      <Edit3 size={18} />
                    </button>
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); onDeleteOrder(o.id); }}
                      className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
             {state.orders.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-20 text-center text-slate-400">
                  <ShoppingCart size={48} className="mx-auto mb-4 opacity-10" />
                  <p className="text-sm font-bold uppercase tracking-widest opacity-50">Belum ada transaksi.</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default OrderManager;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, Calendar as CalendarIcon
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType, LocationType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocalMode, setIsLocalMode] = useState(false);

  useEffect(() => {
    dbService.setStatusListener((isLocal) => {
      setIsLocalMode(isLocal);
    });

    const loadAllData = async () => {
      setIsLoading(true);
      try {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      } catch (e) {
        console.error("Initialization error:", e);
        setIsLocalMode(true);
      } finally {
        setIsLoading(false);
      }
    };
    loadAllData();
  }, []);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  };

  // --- CUSTOMER ACTIONS ---
  const addCustomer = async (c: Customer) => {
    await dbService.upsertCustomer(c);
    setState(prev => ({ ...prev, customers: [c, ...prev.customers] }));
  };

  const updateCustomer = async (c: Customer) => {
    await dbService.upsertCustomer(c);
    setState(prev => {
      const updatedOrders = prev.orders.map(order => {
        if (order.customerId === c.id) {
          const synced = { ...order, customerName: c.name, customerAddress: c.address, customerEmail: c.email, customerType: c.type };
          dbService.upsertOrder(synced);
          return synced;
        }
        return order;
      });
      return {
        ...prev,
        customers: prev.customers.map(item => item.id === c.id ? c : item),
        orders: updatedOrders
      };
    });
  };

  const deleteCustomer = useCallback(async (id: string) => {
    if (!window.confirm('Hapus pelanggan ini? Data invoice lama tetap ada, tapi pelanggan hilang dari daftar master.')) return;

    // Optimistic UI
    setState(prev => ({ ...prev, customers: prev.customers.filter(c => c.id !== id) }));
    await dbService.deleteCustomer(id);
  }, []);

  // --- PRODUCT ACTIONS ---
  const addProduct = async (p: Product) => {
    await dbService.upsertProduct(p);
    setState(prev => ({ ...prev, products: [p, ...prev.products] }));
  };

  const updateProduct = async (p: Product) => {
    await dbService.upsertProduct(p);
    setState(prev => {
      const updatedOrders = prev.orders.map(order => {
        const hasProduct = order.items.some(i => i.productId === p.id);
        if (hasProduct) {
          const updatedItems = order.items.map(item => {
            if (item.productId === p.id) {
              const newPrice = order.customerType === LocationType.LUAR_KOTA ? p.priceLuarKota : p.priceJakarta;
              return { ...item, name: p.name, unitPrice: newPrice };
            }
            return item;
          });
          const newSubtotal = updatedItems.reduce((sum, i) => sum + (i.quantity * i.unitPrice), 0);
          const synced = { ...order, items: updatedItems, subtotal: newSubtotal, total: newSubtotal - order.downPayment };
          dbService.upsertOrder(synced);
          return synced;
        }
        return order;
      });
      return {
        ...prev,
        products: prev.products.map(item => item.id === p.id ? p : item),
        orders: updatedOrders
      };
    });
  };

  const deleteProduct = useCallback(async (id: string) => {
    if (!window.confirm('Hapus barang ini dari daftar master?')) return;

    setState(prev => ({ ...prev, products: prev.products.filter(p => p.id !== id) }));
    await dbService.deleteProduct(id);
  }, []);

  // --- ORDER ACTIONS ---
  const addOrder = async (o: Order) => {
    await dbService.upsertOrder(o);
    setState(prev => ({ ...prev, orders: [o, ...prev.orders], view: 'orders' }));
  };

  const updateOrder = async (updated: Order) => {
    await dbService.upsertOrder(updated);
    setState(prev => ({
      ...prev,
      orders: prev.orders.map(o => o.id === updated.id ? updated : o)
    }));
  };

  const deleteOrder = useCallback(async (id: string) => {
    if (!window.confirm('Hapus pesanan ini secara permanen?')) return;

    setState(prev => ({ ...prev, orders: prev.orders.filter(o => o.id !== id) }));
    await dbService.deleteOrder(id);
  }, []);

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
      <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-slate-500 font-medium animate-pulse text-sm">Menyiapkan Aplikasi...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <header className="md:hidden bg-slate-900 text-white p-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg"><Package size={20} /></div>
          <span className="font-bold">OrderPro AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 hover:bg-slate-800 rounded-lg">
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}

      <aside className={`w-64 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen`}>
        <div className="p-6 hidden md:flex items-center gap-3 border-b border-slate-800">
          <div className="bg-indigo-600 p-2 rounded-lg"><Package className="text-white w-6 h-6" /></div>
          <span className="text-xl font-bold text-white">OrderPro AI</span>
        </div>
        <nav className="flex-1 p-4 space-y-2 mt-4">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Master Data</div>
          <NavItem icon={<Users size={20} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={20} />} label="Barang" active={state.view === 'products'} onClick={() => setView('products')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Transaksi</div>
