import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, Calendar as CalendarIcon
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType, LocationType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isLocalMode, setIsLocalMode] = useState(false);

  useEffect(() => {
    dbService.setStatusListener((isLocal) => {
      setIsLocalMode(isLocal);
    });

    const loadAllData = async () => {
      setIsLoading(true);
      try {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      } catch (e) {
        console.error("Initialization error:", e);
        setIsLocalMode(true);
      } finally {
        setIsLoading(false);
      }
    };
    loadAllData();
  }, []);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  };

  // --- CUSTOMER ACTIONS ---
  const addCustomer = async (c: Customer) => {
    await dbService.upsertCustomer(c);
    setState(prev => ({ ...prev, customers: [c, ...prev.customers] }));
  };

  const updateCustomer = async (c: Customer) => {
    await dbService.upsertCustomer(c);
    setState(prev => {
      const updatedOrders = prev.orders.map(order => {
        if (order.customerId === c.id) {
          const synced = { ...order, customerName: c.name, customerAddress: c.address, customerEmail: c.email, customerType: c.type };
          dbService.upsertOrder(synced);
          return synced;
        }
        return order;
      });
      return {
        ...prev,
        customers: prev.customers.map(item => item.id === c.id ? c : item),
        orders: updatedOrders
      };
    });
  };

  const deleteCustomer = useCallback(async (id: string) => {
    if (!window.confirm('Hapus pelanggan ini? Pelanggan tidak bisa dihapus jika sudah memiliki riwayat pesanan (hapus pesanan terlebih dahulu).')) return;

    try {
      await dbService.deleteCustomer(id);
      setState(prev => ({ ...prev, customers: prev.customers.filter(c => c.id !== id) }));
    } catch (error: any) {
      alert("Gagal menghapus pelanggan: " + (error.message || "Pastikan pelanggan tidak memiliki data pesanan terkait."));
    }
  }, []);

  // --- PRODUCT ACTIONS ---
  const addProduct = async (p: Product) => {
    await dbService.upsertProduct(p);
    setState(prev => ({ ...prev, products: [p, ...prev.products] }));
  };

  const updateProduct = async (p: Product) => {
    await dbService.upsertProduct(p);
    setState(prev => {
      const updatedOrders = prev.orders.map(order => {
        const hasProduct = order.items.some(i => i.productId === p.id);
        if (hasProduct) {
          const updatedItems = order.items.map(item => {
            if (item.productId === p.id) {
              const newPrice = order.customerType === LocationType.LUAR_KOTA ? p.priceLuarKota : p.priceJakarta;
              return { ...item, name: p.name, unitPrice: newPrice };
            }
            return item;
          });
          const newSubtotal = updatedItems.reduce((sum, i) => sum + (i.quantity * i.unitPrice), 0);
          const synced = { ...order, items: updatedItems, subtotal: newSubtotal, total: newSubtotal - order.downPayment };
          dbService.upsertOrder(synced);
          return synced;
        }
        return order;
      });
      return {
        ...prev,
        products: prev.products.map(item => item.id === p.id ? p : item),
        orders: updatedOrders
      };
    });
  };

  const deleteProduct = useCallback(async (id: string) => {
    if (!window.confirm('Hapus barang ini dari katalog?')) return;

    try {
      await dbService.deleteProduct(id);
      setState(prev => ({ ...prev, products: prev.products.filter(p => p.id !== id) }));
    } catch (error: any) {
      alert("Gagal menghapus produk: " + (error.message || "Silakan coba lagi."));
    }
  }, []);

  // --- ORDER ACTIONS ---
  const addOrder = async (o: Order) => {
    await dbService.upsertOrder(o);
    setState(prev => ({ ...prev, orders: [o, ...prev.orders], view: 'orders' }));
  };

  const updateOrder = async (updated: Order) => {
    await dbService.upsertOrder(updated);
    setState(prev => ({
      ...prev,
      orders: prev.orders.map(o => o.id === updated.id ? updated : o)
    }));
  };

  const deleteOrder = useCallback(async (id: string) => {
    if (!window.confirm('Hapus pesanan ini secara permanen?')) return;

    try {
      await dbService.deleteOrder(id);
      setState(prev => ({ ...prev, orders: prev.orders.filter(o => o.id !== id) }));
    } catch (error: any) {
      alert("Gagal menghapus pesanan: " + (error.message || "Silakan coba lagi."));
    }
  }, []);

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
      <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
      <p className="text-slate-500 font-medium animate-pulse text-sm">Menyiapkan Aplikasi...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <header className="md:hidden bg-slate-900 text-white p-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg"><Package size={20} /></div>
          <span className="font-bold">OrderPro AI</span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 hover:bg-slate-800 rounded-lg">
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}

      <aside className={`w-64 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen`}>
        <div className="p-6 hidden md:flex items-center gap-3 border-b border-slate-800">
          <div className="bg-indigo-600 p-2 rounded-lg"><Package className="text-white w-6 h-6" /></div>
          <span className="text-xl font-bold text-white">OrderPro AI</span>
        </div>
        <nav className="flex-1 p-4 space-y-2 mt-4">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Master Data</div>
          <NavItem icon={<Users size={20} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={20} />} label="Barang" active={state.view === 'products'} onClick={() => setView('products')} />
          <div className="pt-4 pb-2 px-2 text-[10px] font-bold uppercase text-slate-500">Transaksi</div>
          <NavItem icon={<ShoppingCart size={20} />} label="Order Masuk" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={20} />} label="Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />
        </nav>
      </aside>

      <main className="flex-1 overflow-y-auto">
        <header className="hidden md:flex bg-white border-b h-16 items-center px-8 sticky top-0 z-30 justify-between">
           <h2 className="text-lg font-semibold text-slate-800 capitalize">{state.view.replace('_', ' ')}</h2>
           <div className="text-sm text-slate-400 font-medium">
             <CalendarIcon size={14} className="inline mr-2" /> 
             {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
           </div>
        </header>

        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} isLocalMode={isLocalMode} />}
          {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
          {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
          {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
          {state.view === 'reports' && <Reports state={state} />}
          {state.view === 'invoice_detail' && state.activeOrder && (
            <div className="animate-in fade-in duration-300">
              <button onClick={() => setView('orders')} className="flex items-center gap-2 text-slate-500 hover:text-slate-800 mb-6 font-bold text-sm bg-white px-4 py-2 rounded-xl shadow-sm border border-slate-100 transition-all">← Kembali</button>
              <InvoiceView order={state.activeOrder} />
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl font-semibold text-sm transition-all ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-100' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    {icon}<span>{label}</span>
  </button>
);

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, TrendingUp, Trophy, 
  Calendar, Search, FileText, Image as ImageIcon, Clock,
  ListOrdered, ChevronRight, Hash, DollarSign, PieChart, BarChart,
  ShoppingCart
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();

    if (type === 'today') {
      // Hari ini
    } else if (type === 'week') {
      start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
      start.setMonth(end.getMonth() - 1);
    } else if (type === 'year') {
      start.setFullYear(end.getFullYear() - 1);
    }

    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower);

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number, revenue: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0, revenue: 0 };
        salesMap[item.productId].qty += item.quantity;
        salesMap[item.productId].revenue += (item.quantity * item.unitPrice);
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + (o.subtotal || 0), 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0)
      .sort((a, b) => b.totalSpent - a.totalSpent);
  }, [state.customers, filteredOrders, filterCustomer]);

  const totalOmzet = useMemo(() => filteredOrders.reduce((sum, o) => sum + (o.subtotal || 0), 0), [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const link = document.createElement('a');
    link.download = `Laporan_OrderPro_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_OrderPro_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 md:space-y-8 pb-20">
      {/* Control Panel */}
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between gap-4">
           <div>
             <h3 className="font-black text-slate-800 text-lg uppercase tracking-tight">Panel Laporan</h3>
             <p className="text-slate-400 text-xs font-medium">Atur parameter laporan sebelum diunduh</p>
           </div>
           <div className="flex gap-2">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 text-[10px] font-black transition-all hover:bg-slate-50"><ImageIcon size={14} /> DOWNLOAD JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black transition-all shadow-lg shadow-indigo-100 hover:bg-indigo-700"><FileText size={14} /> DOWNLOAD PDF</button>
           </div>
        </div>

        <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-50 mt-4 pt-4">
           <span className="text-[10px] font-black text-slate-300 uppercase flex items-center gap-1 mr-2"><Clock size={12}/> Preset Waktu:</span>
           <button onClick={() => setPreset('today')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Hari Ini</button>
           <button onClick={() => setPreset('week')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">7 Hari</button>
           <button onClick={() => setPreset('month')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">30 Hari</button>
           <button onClick={() => setPreset('year')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Tahun Ini</button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dari Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sampai Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Pelanggan</label>
            <select className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cari Keyword</label>
            <div className="relative">
              <input type="text" placeholder="No. Inv / Nama..." className="w-full pl-8 pr-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-3 text-slate-300" size={14} />
            </div>
          </div>
        </div>
      </div>

      {/* Exportable Area */}
      <div ref={reportRef} className="bg-white p-8 md:p-16 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-12 text-slate-900 overflow-hidden" style={{ width: '100%', maxWidth: '1000px', margin: '0 auto' }}>
        {/* Report Header */}
        <div className="flex justify-between items-start border-b-4 border-slate-900 pb-10">
           <div>
              <h1 className="text-4xl font-black tracking-tighter uppercase mb-2">Laporan Bisnis</h1>
              <p className="text-slate-400 text-xs font-black uppercase tracking-[0.3em]">OrderPro Management System</p>
           </div>
           <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">Periode Laporan</p>
              <p className="text-sm font-bold bg-slate-900 text-white px-3 py-1 rounded-lg">
                {startDate ? new Date(startDate).toLocaleDateString('id-ID', { dateStyle: 'medium' }) : 'Awal'} 
                <span className="mx-2 opacity-50">s/d</span> 
                {endDate ? new Date(endDate).toLocaleDateString('id-ID', { dateStyle: 'medium' }) : 'Sekarang'}
              </p>
           </div>
        </div>

        {/* Global Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <PieChart size={14} className="text-indigo-500" /> Total Omzet
              </p>
              <h2 className="text-3xl font-black text-indigo-600 tracking-tighter">Rp {totalOmzet.toLocaleString()}</h2>
           </div>
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Hash size={14} className="text-indigo-500" /> Total Pesanan
              </p>
              <h2 className="text-3xl font-black text-slate-800 tracking-tighter">{filteredOrders.length} Order</h2>
           </div>
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Users size={14} className="text-indigo-500" /> Pelanggan Aktif
              </p>
              <h2 className="text-3xl font-black text-slate-800 tracking-tighter">{customerReports.length} Nama</h2>
           </div>
        </div>

        {/* Top Products Section */}
        <section>
           <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] mb-6 flex items-center gap-2">
             <Trophy size={16} className="text-amber-500" /> Produk Terlaris (Top {Math.min(5, productSales.length)})
           </h3>
           <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
              {productSales.slice(0, 5).map((p, i) => (
                <div key={i} className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl bg-white shadow-sm">
                   <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-600 font-black text-sm">#{i+1}</div>
                   <div>
                      <p className="text-xs font-black text-slate-800 truncate max-w-[120px]">{p.name}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.qty} Unit Terjual</p>
                   </div>
                </div>
              ))}
              {productSales.length === 0 && <p className="text-xs italic text-slate-400 opacity-50">Tidak ada data produk.</p>}
           </div>
        </section>

        {/* Detailed Transactions List */}
        <section>
          <div className="flex justify-between items-end mb-6">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] flex items-center gap-2">
              <ListOrdered size={16} className="text-indigo-500" /> Rincian Transaksi Terperinci
            </h3>
            <p className="text-[9px] font-bold text-slate-300 italic">*Menampilkan rincian produk per invoice</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-900 text-white text-[9px] font-black uppercase tracking-widest">
                <tr>
                  <th className="px-5 py-5 rounded-tl-2xl">Inv / Tanggal</th>
                  <th className="px-5 py-5">Detail Pelanggan</th>
                  <th className="px-5 py-5">Produk & Kuantitas</th>
                  <th className="px-5 py-5 text-right rounded-tr-2xl">Subtotal (Rp)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 border-x border-b border-slate-100 rounded-b-2xl">
                {filteredOrders.map((order, idx) => (
                  <tr key={order.id} className={idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/40'}>
                    <td className="px-5 py-6">
                      <p className="text-xs font-black text-slate-900 mb-1">{order.invoiceNumber}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">
                        {new Date(order.orderDate).toLocaleDateString('id-ID', { day: '2-digit', month: 'long', year: 'numeric' })}
                      </p>
                    </td>
                    <td className="px-5 py-6">
                      <p className="text-xs font-black text-slate-800">{order.customerName}</p>
                      <p className="text-[9px] text-slate-400 font-medium uppercase tracking-widest mb-1">{order.customerType}</p>
                      {order.customerEmail && <p className="text-[9px] text-indigo-400 font-medium">{order.customerEmail}</p>}
                    </td>
                    <td className="px-5 py-6">
                      <div className="space-y-1.5">
                        {order.items.map((item, i) => (
                          <div key={i} className="flex justify-between items-baseline gap-4 group">
                             <span className="text-[10px] font-bold text-slate-600 flex items-center gap-1">
                               <ChevronRight size={8} className="text-indigo-300" /> {item.name}
                             </span>
                             <span className="text-[10px] font-black text-slate-400 whitespace-nowrap bg-slate-100 px-1.5 py-0.5 rounded uppercase tracking-tighter">{item.quantity} QTY</span>
                          </div>
                        ))}
                      </div>
                    </td>
                    <td className="px-5 py-6 text-right">
                      <p className="text-xs font-black text-slate-900">Rp {order.subtotal.toLocaleString()}</p>
                    </td>
                  </tr>
                ))}
                {filteredOrders.length === 0 && (
                  <tr>
                    <td colSpan={4} className="px-6 py-32 text-center">
                       <ShoppingCart className="mx-auto mb-4 opacity-5 text-slate-900" size={60} />
                       <p className="text-slate-300 font-black uppercase tracking-widest">Tidak ada data transaksi ditemukan</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </section>

        {/* Footer info removed as per user request */}
      </div>
    </div>
  );
};

