import { supabase } from '../lib/supabase';
import { Customer, Product, Order } from '../types';

const LOCAL_STORAGE_KEY = 'orderpro_data_v3';

const getLocalData = () => {
  const data = localStorage.getItem(LOCAL_STORAGE_KEY);
  return data ? JSON.parse(data) : { customers: [], products: [], orders: [] };
};

const saveLocalData = (data: any) => {
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
};

// Helpers to map between DB (snake_case) and App (camelCase)
const mapProductFromDB = (p: any): Product => ({
  id: p.id,
  name: p.name || 'Produk Tanpa Nama',
  description: p.description || '',
  priceJakarta: Number(p.price_jakarta || 0),
  priceLuarKota: Number(p.price_luar_kota || 0)
});

const mapProductToDB = (p: Product) => ({
  id: p.id,
  name: p.name,
  description: p.description,
  price_jakarta: p.priceJakarta,
  price_luar_kota: p.priceLuarKota
});

const mapOrderFromDB = (o: any): Order => ({
  id: o.id,
  invoiceNumber: o.invoice_number || 'INV-TEMP',
  customerId: o.customer_id || '',
  customerName: o.customer_name || 'Pelanggan',
  customerEmail: o.customer_email || '',
  customerType: o.customer_type || 'Jakarta',
  customerAddress: o.customer_address || '',
  orderDate: o.order_date || new Date().toISOString(),
  status: o.status || 'PENDING',
  items: o.items || [],
  subtotal: Number(o.subtotal || 0),
  downPayment: Number(o.down_payment || 0),
  payments: o.payments || [],
  total: Number(o.total || 0),
  notes: o.notes || ''
});

const mapOrderToDB = (o: Order) => ({
  id: o.id,
  invoice_number: o.invoiceNumber,
  customer_id: o.customerId,
  customer_name: o.customerName,
  customer_email: o.customerEmail,
  customer_type: o.customerType,
  customer_address: o.customerAddress,
  order_date: o.orderDate,
  status: o.status,
  items: o.items,
  subtotal: o.subtotal,
  down_payment: o.downPayment,
  payments: o.payments,
  total: o.total,
  notes: o.notes
});

export const dbService = {
  useLocalStorage: false,
  statusListener: null as ((isLocal: boolean) => void) | null,

  setStatusListener(listener: (isLocal: boolean) => void) {
    this.statusListener = listener;
  },

  notifyStatus(isLocal: boolean) {
    this.useLocalStorage = isLocal;
    if (this.statusListener) this.statusListener(isLocal);
  },

  async handleSupabaseError(error: any) {
    const message = error?.message || (typeof error === 'string' ? error : JSON.stringify(error));
    console.error("Supabase Connection Issue:", message);

    // Kode error 42703 = Undefined Column (kolom tidak ditemukan)
    const criticalErrorCodes = ['42P01', 'PGRST116', '42703', '42501', 'PT404'];
    if (criticalErrorCodes.includes(error.code) || error.status === 404) {
      this.notifyStatus(true);
    }
    return error;
  },

  // Customers
  async getCustomers(): Promise<Customer[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().customers;
    try {
      const { data, error } = await supabase.from('customers').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().customers;
      }
      return data || [];
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().customers;
    }
  },
  async upsertCustomer(customer: Customer) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.customers.findIndex((c: any) => c.id === customer.id);
      if (index > -1) data.customers[index] = customer;
      else data.customers.unshift(customer);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').upsert(customer);
    if (error) await this.handleSupabaseError(error);
  },
  async deleteCustomer(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.customers = data.customers.filter((c: any) => c.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },

  // Products
  async getProducts(): Promise<Product[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().products;
    try {
      const { data, error } = await supabase.from('products').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().products;
      }
      return (data || []).map(mapProductFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().products;
    }
  },
  async upsertProduct(product: Product) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.products.findIndex((p: any) => p.id === product.id);
      if (index > -1) data.products[index] = product;
      else data.products.unshift(product);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').upsert(mapProductToDB(product));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteProduct(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.products = data.products.filter((p: any) => p.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },

  // Orders
  async getOrders(): Promise<Order[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().orders;
    try {
      const { data, error } = await supabase.from('orders').select('*').order('order_date', { ascending: false });
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().orders;
      }
      return (data || []).map(mapOrderFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().orders;
    }
  },
  async upsertOrder(order: Order) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.orders.findIndex((o: any) => o.id === order.id);
      if (index > -1) data.orders[index] = order;
      else data.orders.unshift(order);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').upsert(mapOrderToDB(order));
    if (error) await this.handleSupabaseError(error);
  },
  async deleteOrder(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.orders = data.orders.filter((o: any) => o.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  }
};

import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, TrendingUp, Trophy, 
  Calendar, Search, FileText, Image as ImageIcon, Clock,
  ListOrdered, ChevronRight, Hash, DollarSign, PieChart, BarChart,
  ShoppingCart
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();

    if (type === 'today') {
      // Hari ini
    } else if (type === 'week') {
      start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
      start.setMonth(end.getMonth() - 1);
    } else if (type === 'year') {
      start.setFullYear(end.getFullYear() - 1);
    }

    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower);

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number, revenue: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0, revenue: 0 };
        salesMap[item.productId].qty += item.quantity;
        salesMap[item.productId].revenue += (item.quantity * item.unitPrice);
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + (o.subtotal || 0), 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0)
      .sort((a, b) => b.totalSpent - a.totalSpent);
  }, [state.customers, filteredOrders, filterCustomer]);

  const totalOmzet = useMemo(() => filteredOrders.reduce((sum, o) => sum + (o.subtotal || 0), 0), [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const link = document.createElement('a');
    link.download = `Laporan_OrderPro_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_OrderPro_${new Date().getTime()}.pdf`);
  };

