-- SOLUSI PERBAIKAN: Pastikan kolom ada dan RLS mati total agar aplikasi bisa HAPUS/TAMBAH
ALTER TABLE orders ADD COLUMN IF NOT EXISTS order_date timestamp with time zone DEFAULT now();
ALTER TABLE orders ADD COLUMN IF NOT EXISTS invoice_number text;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS customer_name text;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS customer_type text;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS items jsonb;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS subtotal numeric;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS total numeric;

-- MATIKAN KEBIJAKAN KEAMANAN (RLS) AGAR CRUD BERFUNGSI 100%
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE products DISABLE ROW LEVEL SECURITY;

-- Berikan izin akses publik penuh agar fitur HAPUS bekerja
GRANT ALL ON TABLE orders TO anon, authenticated;
GRANT ALL ON TABLE customers TO anon, authenticated;
GRANT ALL ON TABLE products TO anon, authenticated;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated;
  `.trim();

  const resetSql = `
-- RESET TOTAL: Hapus dan buat ulang semua tabel dengan struktur benar
DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS products;
DROP TABLE IF EXISTS customers;

CREATE TABLE customers (
  id text PRIMARY KEY,
  name text NOT NULL,
  email text,
  address text,
  type text NOT NULL
);

CREATE TABLE products (
  id text PRIMARY KEY,
  name text NOT NULL,
  description text,
  price_jakarta numeric NOT NULL,
  price_luar_kota numeric NOT NULL
);

CREATE TABLE orders (
  id text PRIMARY KEY,
  invoice_number text NOT NULL,
  customer_id text REFERENCES customers(id),
  customer_name text NOT NULL,
  customer_email text,
  customer_type text NOT NULL,
  customer_address text,
  order_date timestamp with time zone NOT NULL DEFAULT now(),
  status text NOT NULL,
  items jsonb NOT NULL,
  subtotal numeric NOT NULL,
  down_payment numeric NOT NULL DEFAULT 0,
  payments jsonb NOT NULL DEFAULT '[]',
  total numeric NOT NULL,
  notes text
);

-- MATIKAN RLS UNTUK MEMASTIKAN FITUR HAPUS BERJALAN
ALTER TABLE customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
ALTER TABLE orders DISABLE ROW LEVEL SECURITY;

GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated;
  `.trim();

  const currentSql = sqlType === 'migration' ? migrationSql : resetSql;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentSql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Halo, Admin Toko! 👋</h1>
          <p className="text-slate-500 text-sm">Berikut adalah ringkasan bisnis Anda hari ini.</p>
        </div>
        {isLocalMode && (
           <button 
            onClick={() => window.location.reload()}
            className="flex items-center gap-2 bg-indigo-600 px-5 py-2.5 rounded-xl text-xs font-bold text-white hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200"
           >
             <RefreshCw size={14} className="animate-spin-slow" />
             Hubungkan Ulang
           </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link as ViewType)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow cursor-pointer group"
          >
            <div className="flex justify-between items-start">
              <div className={`${stat.color} p-3 rounded-xl`}>
                {stat.icon}
              </div>
              <ArrowUpRight className="text-slate-300 group-hover:text-indigo-500 transition-colors w-4 h-4" />
            </div>
            <div className="mt-4">
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {isLocalMode && (
        <div className="bg-rose-50 border border-rose-200 rounded-3xl p-6 md:p-8 shadow-sm">
           <div className="flex items-center gap-3 mb-6 text-rose-700">
             <div className="bg-rose-100 p-3 rounded-2xl">
                <AlertTriangle size={28} />
             </div>
             <div>
                <h3 className="text-xl font-black italic">Masalah Izin Database!</h3>
                <p className="text-sm font-medium opacity-80">Aplikasi tidak bisa melakukan HAPUS data ke Supabase karena kebijakan keamanan (RLS).</p>
             </div>
           </div>

           <div className="bg-white rounded-2xl p-6 border border-rose-100 mb-6 shadow-sm">
              <div className="flex flex-col sm:flex-row gap-4 mb-6">
                <button 
                  onClick={() => setSqlType('migration')}
                  className={`flex-1 p-4 rounded-xl border-2 transition-all text-left ${sqlType === 'migration' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 bg-slate-50'}`}
                >
                  <div className="flex items-center gap-2 mb-1">
                    <Wrench size={16} className={sqlType === 'migration' ? 'text-indigo-600' : 'text-slate-400'} />
                    <span className={`text-sm font-bold ${sqlType === 'migration' ? 'text-indigo-900' : 'text-slate-600'}`}>1. Buka Akses Hapus</span>
                  </div>
                  <p className="text-[10px] text-slate-500 font-medium">Hanya mematikan RLS dan memberikan izin publik.</p>
                </button>
                <button 
                  onClick={() => setSqlType('reset')}
                  className={`flex-1 p-4 rounded-xl border-2 transition-all text-left ${sqlType === 'reset' ? 'border-rose-600 bg-rose-50' : 'border-slate-100 bg-slate-50'}`}
                >
                  <div className="flex items-center gap-2 mb-1">
                    <RefreshCw size={16} className={sqlType === 'reset' ? 'text-rose-600' : 'text-slate-400'} />
                    <span className={`text-sm font-bold ${sqlType === 'reset' ? 'text-rose-900' : 'text-slate-600'}`}>2. Reset Total DB</span>
                  </div>
                  <p className="text-[10px] text-slate-500 font-medium">Buat ulang semua tabel (Hati-hati: Data terhapus).</p>
                </button>
              </div>

              <div className="relative group">
                <div className="absolute top-0 left-0 right-0 h-8 bg-slate-900 rounded-t-2xl flex items-center px-4 gap-1.5">
                   <div className="w-2.5 h-2.5 rounded-full bg-rose-500" />
                   <div className="w-2.5 h-2.5 rounded-full bg-amber-500" />
                   <div className="w-2.5 h-2.5 rounded-full bg-emerald-500" />
                   <span className="text-[10px] text-slate-500 font-bold ml-2 font-mono uppercase tracking-widest">Supabase SQL Editor</span>
                </div>
                <pre className="bg-slate-900 text-indigo-300 p-8 pt-12 rounded-2xl text-[10px] md:text-xs overflow-x-auto font-mono leading-relaxed max-h-64 overflow-y-auto shadow-inner border border-slate-800">
                  {currentSql}
                </pre>
                <button 
                  onClick={copyToClipboard}
                  className="absolute bottom-4 right-4 bg-indigo-600 hover:bg-indigo-700 px-4 py-2 rounded-xl text-white transition-all flex items-center gap-2 text-xs font-bold shadow-lg"
                >
                  {copied ? <Check size={14} /> : <Copy size={14} />}
                  {copied ? 'Copied!' : 'Copy Code'}
                </button>
              </div>
           </div>

           <div className="flex items-start gap-3 text-rose-600">
              <Terminal size={18} className="shrink-0 mt-0.5" />
              <p className="text-xs font-medium leading-relaxed">
                Copy kode di atas, buka <b>SQL Editor</b> di Dashboard Supabase, Paste, dan klik <b>RUN</b>. Langkah ini mematikan keamanan database (RLS) agar tombol HAPUS di aplikasi bisa berfungsi.
              </p>
           </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Transaksi Terakhir</h3>
            {state.orders.length > 0 ? (
              <div className="space-y-4">
                {state.orders.slice(0, 5).map((order) => (
                  <div key={order.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-xl hover:bg-slate-100/80 transition-colors group">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center border border-slate-200 shadow-sm text-indigo-600">
                        <ShoppingBag size={18} />
                      </div>
                      <div className="min-w-0">
                        <p className="text-sm font-bold text-slate-800 truncate">{order.customerName}</p>
                        <p className="text-xs text-slate-400">{order.invoiceNumber}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <div className="text-right">
                        <p className="text-sm font-bold text-slate-800">Rp {(order.total || 0).toLocaleString()}</p>
                        <p className="text-[10px] text-slate-400">{new Date(order.orderDate).toLocaleDateString()}</p>
                      </div>
                      <button 
                        onClick={(e) => { e.stopPropagation(); onDeleteOrder(order.id); }}
