                        title="Hapus Order"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                <ShoppingBag size={48} className="mb-4 opacity-20" />
                <p>Belum ada transaksi</p>
              </div>
            )}
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-indigo-900 rounded-3xl p-8 text-white relative overflow-hidden flex flex-col justify-between h-fit shadow-xl shadow-indigo-100">
             <div className="absolute top-0 right-0 p-8 opacity-10">
               <ShoppingBag size={180} />
             </div>
             <div className="relative z-10">
               <h3 className="text-2xl font-bold mb-2">Siap Jualan?</h3>
               <p className="text-indigo-200 text-sm leading-relaxed mb-8">
