import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Package, Users, TrendingUp, Trophy, 
  Calendar, Search, FileText, Image as ImageIcon, Clock,
  ListOrdered, ChevronRight, Hash, DollarSign, PieChart, BarChart,
  ShoppingCart
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [filterProduct, setFilterProduct] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month' | 'year') => {
    const end = new Date();
    const start = new Date();

    if (type === 'today') {
      // Hari ini
    } else if (type === 'week') {
      start.setDate(end.getDate() - 7);
    } else if (type === 'month') {
      start.setMonth(end.getMonth() - 1);
    } else if (type === 'year') {
      start.setFullYear(end.getFullYear() - 1);
    }

    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);

      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }

      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const matchesProduct = filterProduct === 'all' || order.items.some(i => i.productId === filterProduct);
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || 
        order.customerName.toLowerCase().includes(searchLower) || 
        order.invoiceNumber.toLowerCase().includes(searchLower);

      return matchesTime && matchesCustomer && matchesProduct && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, filterProduct, searchTerm]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number, revenue: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (filterProduct !== 'all' && item.productId !== filterProduct) return;
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0, revenue: 0 };
        salesMap[item.productId].qty += item.quantity;
        salesMap[item.productId].revenue += (item.quantity * item.unitPrice);
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders, filterProduct]);

  const customerReports = useMemo(() => {
    return state.customers
      .filter(c => filterCustomer === 'all' || c.id === filterCustomer)
      .map(customer => {
        const orders = filteredOrders.filter(o => o.customerId === customer.id);
        const totalSpent = orders.reduce((sum, o) => sum + (o.subtotal || 0), 0);
        return { ...customer, orderCount: orders.length, totalSpent };
      })
      .filter(c => c.orderCount > 0)
      .sort((a, b) => b.totalSpent - a.totalSpent);
  }, [state.customers, filteredOrders, filterCustomer]);

  const totalOmzet = useMemo(() => filteredOrders.reduce((sum, o) => sum + (o.subtotal || 0), 0), [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const link = document.createElement('a');
    link.download = `Laporan_OrderPro_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { 
      scale: 2, 
      backgroundColor: '#ffffff',
      logging: false,
      useCORS: true
    });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_OrderPro_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 md:space-y-8 pb-20">
      {/* Control Panel */}
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between gap-4">
           <div>
             <h3 className="font-black text-slate-800 text-lg uppercase tracking-tight">Panel Laporan</h3>
             <p className="text-slate-400 text-xs font-medium">Atur parameter laporan sebelum diunduh</p>
           </div>
           <div className="flex gap-2">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 text-[10px] font-black transition-all hover:bg-slate-50"><ImageIcon size={14} /> DOWNLOAD JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black transition-all shadow-lg shadow-indigo-100 hover:bg-indigo-700"><FileText size={14} /> DOWNLOAD PDF</button>
           </div>
        </div>

        <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-50 mt-4 pt-4">
           <span className="text-[10px] font-black text-slate-300 uppercase flex items-center gap-1 mr-2"><Clock size={12}/> Preset Waktu:</span>
           <button onClick={() => setPreset('today')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Hari Ini</button>
           <button onClick={() => setPreset('week')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">7 Hari</button>
           <button onClick={() => setPreset('month')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">30 Hari</button>
           <button onClick={() => setPreset('year')} className="px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-[10px] font-bold hover:bg-indigo-50 hover:text-indigo-600 transition-colors">Tahun Ini</button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Dari Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Sampai Tanggal</label>
            <input type="date" className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Pelanggan</label>
            <select className="w-full px-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={filterCustomer} onChange={(e) => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cari Keyword</label>
            <div className="relative">
              <input type="text" placeholder="No. Inv / Nama..." className="w-full pl-8 pr-4 py-2.5 rounded-xl bg-slate-50 border border-slate-100 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-3 text-slate-300" size={14} />
            </div>
          </div>
        </div>
      </div>

      {/* Exportable Area */}
      <div ref={reportRef} className="bg-white p-8 md:p-16 rounded-[2.5rem] shadow-sm border border-slate-100 space-y-12 text-slate-900 overflow-hidden" style={{ width: '100%', maxWidth: '1000px', margin: '0 auto' }}>
        {/* Report Header */}
        <div className="flex justify-between items-start border-b-4 border-slate-900 pb-10">
           <div>
              <h1 className="text-4xl font-black tracking-tighter uppercase mb-2">Laporan Bisnis</h1>
              <p className="text-slate-400 text-xs font-black uppercase tracking-[0.3em]">OrderPro Management System</p>
           </div>
           <div className="text-right">
              <p className="text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">Periode Laporan</p>
              <p className="text-sm font-bold bg-slate-900 text-white px-3 py-1 rounded-lg">
                {startDate ? new Date(startDate).toLocaleDateString('id-ID', { dateStyle: 'medium' }) : 'Awal'} 
                <span className="mx-2 opacity-50">s/d</span> 
                {endDate ? new Date(endDate).toLocaleDateString('id-ID', { dateStyle: 'medium' }) : 'Sekarang'}
              </p>
           </div>
        </div>

        {/* Global Stats */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <PieChart size={14} className="text-indigo-500" /> Total Omzet
              </p>
              <h2 className="text-3xl font-black text-indigo-600 tracking-tighter">Rp {totalOmzet.toLocaleString()}</h2>
           </div>
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Hash size={14} className="text-indigo-500" /> Total Pesanan
              </p>
              <h2 className="text-3xl font-black text-slate-800 tracking-tighter">{filteredOrders.length} Order</h2>
           </div>
           <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <Users size={14} className="text-indigo-500" /> Pelanggan Aktif
              </p>
              <h2 className="text-3xl font-black text-slate-800 tracking-tighter">{customerReports.length} Nama</h2>
           </div>
        </div>

        {/* Top Products Section */}
        <section>
           <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.4em] mb-6 flex items-center gap-2">
             <Trophy size={16} className="text-amber-500" /> Produk Terlaris (Top {Math.min(5, productSales.length)})
           </h3>
           <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
              {productSales.slice(0, 5).map((p, i) => (
                <div key={i} className="flex items-center gap-4 p-4 border border-slate-100 rounded-2xl bg-white shadow-sm">
                   <div className="w-10 h-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-600 font-black text-sm">#{i+1}</div>
                   <div>
                      <p className="text-xs font-black text-slate-800 truncate max-w-[120px]">{p.name}</p>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{p.qty} Unit Terjual</p>
                   </div>
