export const dbService = {
  useLocalStorage: false,
  statusListener: null as ((isLocal: boolean) => void) | null,

  setStatusListener(listener: (isLocal: boolean) => void) {
    this.statusListener = listener;
  },

  notifyStatus(isLocal: boolean) {
    this.useLocalStorage = isLocal;
    if (this.statusListener) this.statusListener(isLocal);
  },

  async handleSupabaseError(error: any) {
    const message = error?.message || (typeof error === 'string' ? error : JSON.stringify(error));
    console.error("Supabase Operation Error:", message);

    // Check for connectivity or schema issues to trigger fallback
    const criticalErrorCodes = ['42P01', 'PGRST116', '42703', '42501', 'PT404', 'ECONNREFUSED'];
    if (criticalErrorCodes.includes(error.code) || error.status === 404 || !navigator.onLine) {
      this.notifyStatus(true);
    }
    return error;
  },

  // Customers
  async getCustomers(): Promise<Customer[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().customers;
    try {
      const { data, error } = await supabase.from('customers').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().customers;
      }
      return data || [];
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().customers;
    }
  },
  async upsertCustomer(customer: Customer) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.customers.findIndex((c: any) => c.id === customer.id);
      if (index > -1) data.customers[index] = customer;
      else data.customers.unshift(customer);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').upsert(customer);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },
  async deleteCustomer(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.customers = data.customers.filter((c: any) => c.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('customers').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },

  // Products
  async getProducts(): Promise<Product[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().products;
    try {
      const { data, error } = await supabase.from('products').select('*').order('name');
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().products;
      }
      return (data || []).map(mapProductFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().products;
    }
  },
  async upsertProduct(product: Product) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.products.findIndex((p: any) => p.id === product.id);
      if (index > -1) data.products[index] = product;
      else data.products.unshift(product);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').upsert(mapProductToDB(product));
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },
  async deleteProduct(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.products = data.products.filter((p: any) => p.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('products').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },

  // Orders
  async getOrders(): Promise<Order[]> {
    if (!supabase || this.useLocalStorage) return getLocalData().orders;
    try {
      const { data, error } = await supabase.from('orders').select('*').order('order_date', { ascending: false });
      if (error) {
        await this.handleSupabaseError(error);
        return getLocalData().orders;
      }
      return (data || []).map(mapOrderFromDB);
    } catch (e) {
      this.notifyStatus(true);
      return getLocalData().orders;
    }
  },
  async upsertOrder(order: Order) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      const index = data.orders.findIndex((o: any) => o.id === order.id);
      if (index > -1) data.orders[index] = order;
      else data.orders.unshift(order);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').upsert(mapOrderToDB(order));
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  },
  async deleteOrder(id: string) {
    if (!supabase || this.useLocalStorage) {
      const data = getLocalData();
      data.orders = data.orders.filter((o: any) => o.id !== id);
      saveLocalData(data);
      return;
    }
    const { error } = await supabase.from('orders').delete().eq('id', id);
    if (error) {
      await this.handleSupabaseError(error);
      throw error;
    }
  }
};

