  isLocalMode: boolean;
  onDeleteOrder: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ state, onNavigate, isLocalMode, onDeleteOrder }) => {
  const [copied, setCopied] = useState(false);
  const [sqlType, setSqlType] = useState<'migration' | 'reset'>('migration');

  const totalRevenue = state.orders.reduce((acc, curr) => acc + (curr.total || 0), 0);
  const todayOrders = state.orders.filter(o => 
    new Date(o.orderDate).toDateString() === new Date().toDateString()
  ).length;

  const stats = [
    { label: 'Total Sisa Tagihan', value: `Rp ${(totalRevenue || 0).toLocaleString()}`, icon: <DollarSign className="text-emerald-500" />, color: 'bg-emerald-50', link: 'orders' },
    { label: 'Order Hari Ini', value: todayOrders, icon: <ShoppingBag className="text-indigo-500" />, color: 'bg-indigo-50', link: 'orders' },
    { label: 'Total Pelanggan', value: state.customers.length, icon: <Users className="text-blue-500" />, color: 'bg-blue-50', link: 'customers' },
    { label: 'Stok Barang', value: state.products.length, icon: <TrendingUp className="text-amber-500" />, color: 'bg-amber-50', link: 'products' },
  ];

  const migrationSql = `
-- 1. MATIKAN KEAMANAN BARIS (RLS) --
ALTER TABLE IF EXISTS orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS products DISABLE ROW LEVEL SECURITY;

-- 2. HAPUS SEMUA KEBIJAKAN YANG ADA (FORCE DELETE) --
DROP POLICY IF EXISTS "Enable all access" ON orders;
DROP POLICY IF EXISTS "Enable all access" ON customers;
DROP POLICY IF EXISTS "Enable all access" ON products;

-- 3. BERIKAN IZIN AKSES PENUH KE PUBLIK --
GRANT ALL ON SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL FUNCTIONS IN SCHEMA public TO anon, authenticated, postgres;

-- 4. PASTIKAN STRUKTUR KOLOM LENGKAP --
ALTER TABLE orders ADD COLUMN IF NOT EXISTS subtotal numeric DEFAULT 0;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS total numeric DEFAULT 0;
ALTER TABLE orders ADD COLUMN IF NOT EXISTS payments jsonb DEFAULT '[]';
  `.trim();

  const resetSql = `
-- RESET TOTAL (SEMUA DATA AKAN DIHAPUS) --
DROP TABLE IF EXISTS orders CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS customers CASCADE;

CREATE TABLE customers (
  id text PRIMARY KEY,
  name text NOT NULL,
  email text,
  address text,
  type text NOT NULL
);

CREATE TABLE products (
  id text PRIMARY KEY,
  name text NOT NULL,
  description text,
  price_jakarta numeric NOT NULL,
  price_luar_kota numeric NOT NULL
);

CREATE TABLE orders (
  id text PRIMARY KEY,
  invoice_number text NOT NULL,
  customer_id text REFERENCES customers(id),
  customer_name text NOT NULL,
  customer_email text,
  customer_type text NOT NULL,
  customer_address text,
  order_date timestamp with time zone NOT NULL DEFAULT now(),
  status text NOT NULL,
  items jsonb NOT NULL,
  subtotal numeric NOT NULL,
  down_payment numeric NOT NULL DEFAULT 0,
  payments jsonb NOT NULL DEFAULT '[]',
  total numeric NOT NULL,
  notes text
);

ALTER TABLE orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE products DISABLE ROW LEVEL SECURITY;

GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, postgres;
  `.trim();

  const currentSql = sqlType === 'migration' ? migrationSql : resetSql;

  const copyToClipboard = () => {
    try {
      navigator.clipboard.writeText(currentSql);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      alert("Gagal menyalin. Silakan blok kode dan salin manual.");
    }
  };

  const handleResetCache = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (window.confirm('Bersihkan semua data lokal? Jika database Supabase Anda belum benar, data yang baru diinput mungkin akan hilang. Klik OK untuk muat ulang.')) {
      localStorage.clear();
      window.location.reload();
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Dashboard Admin 👋</h1>
          <p className="text-slate-500 text-sm">Kelola pesanan dan inventaris Anda di satu tempat.</p>
        </div>
        <div className="flex gap-2">
           <button 
            type="button"
            onClick={handleResetCache}
            className="flex items-center gap-2 bg-slate-100 hover:bg-slate-200 px-4 py-2.5 rounded-xl text-[10px] font-black text-slate-600 transition-all border border-slate-300 shadow-sm"
           >
             <RefreshCw size={12} />
             RESET CACHE
           </button>
           {isLocalMode && (
              <button 
                type="button"
                onClick={() => window.location.reload()}
                className="flex items-center gap-2 bg-indigo-600 px-5 py-2.5 rounded-xl text-xs font-bold text-white hover:bg-indigo-700 transition-all shadow-lg"
              >
                Hubungkan Database
              </button>
           )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link as ViewType)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow cursor-pointer group"
          >
            <div className="flex justify-between items-start">
              <div className={`${stat.color} p-3 rounded-xl`}>
                {stat.icon}
              </div>
              <ArrowUpRight className="text-slate-300 group-hover:text-indigo-500 transition-colors w-4 h-4" />
            </div>
            <div className="mt-4">
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      <div className="bg-amber-50 border border-amber-200 rounded-3xl p-6 md:p-8 shadow-sm">
         <div className="flex items-center gap-3 mb-6 text-amber-700">
           <div className="bg-amber-100 p-3 rounded-2xl">
