const Dashboard: React.FC<DashboardProps> = ({ state, onNavigate, isLocalMode, onDeleteOrder }) => {
  const [copied, setCopied] = useState(false);
  const [sqlType, setSqlType] = useState<'migration' | 'reset'>('migration');

  const totalRevenue = state.orders.reduce((acc, curr) => acc + (curr.total || 0), 0);
  const todayOrders = state.orders.filter(o => 
    new Date(o.orderDate).toDateString() === new Date().toDateString()
  ).length;

  const stats = [
    { label: 'Total Sisa Tagihan', value: `Rp ${(totalRevenue || 0).toLocaleString()}`, icon: <MoneyIcon className="text-emerald-500" />, color: 'bg-emerald-50', link: 'orders' },
    { label: 'Order Hari Ini', value: todayOrders, icon: <CartIcon className="text-indigo-500" />, color: 'bg-indigo-50', link: 'orders' },
    { label: 'Total Pelanggan', value: state.customers.length, icon: <UsersIcon className="text-blue-500" />, color: 'bg-blue-50', link: 'customers' },
    { label: 'Stok Barang', value: state.products.length, icon: <ChartIcon className="text-amber-500" />, color: 'bg-amber-50', link: 'products' },
  ];

  const migrationSql = `
-- 1. PAKSA MATIKAN RLS (KEAMANAN BARIS) --
ALTER TABLE IF EXISTS orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS products DISABLE ROW LEVEL SECURITY;

-- 2. HAPUS SEMUA POLICY LAMA --
DROP POLICY IF EXISTS "Enable all access" ON orders;
DROP POLICY IF EXISTS "Enable all access" ON customers;
DROP POLICY IF EXISTS "Enable all access" ON products;

-- 3. BERIKAN IZIN PUBLIK PENUH --
GRANT ALL ON SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, postgres;
GRANT ALL ON ALL FUNCTIONS IN SCHEMA public TO anon, authenticated, postgres;
  `.trim();

  const resetSql = `
-- ⚠️ RESET TOTAL (HAPUS SEMUA DATA) --
DROP TABLE IF EXISTS orders CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS customers CASCADE;

CREATE TABLE customers (id text PRIMARY KEY, name text NOT NULL, email text, address text, type text NOT NULL);
CREATE TABLE products (id text PRIMARY KEY, name text NOT NULL, description text, price_jakarta numeric NOT NULL, price_luar_kota numeric NOT NULL);
CREATE TABLE orders (
  id text PRIMARY KEY, invoice_number text NOT NULL, customer_id text REFERENCES customers(id),
  customer_name text NOT NULL, customer_email text, customer_type text NOT NULL,
  customer_address text, order_date timestamp with time zone NOT NULL DEFAULT now(),
  status text NOT NULL, items jsonb NOT NULL, subtotal numeric NOT NULL,
  down_payment numeric NOT NULL DEFAULT 0, payments jsonb NOT NULL DEFAULT '[]',
  total numeric NOT NULL, notes text
);

ALTER TABLE orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE products DISABLE ROW LEVEL SECURITY;
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated, postgres;
  `.trim();

  const currentSql = sqlType === 'migration' ? migrationSql : resetSql;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(currentSql).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleResetCache = () => {
    // Tanpa e.preventDefault() untuk memastikan klik tembus
