        </div>
        <div className="flex gap-2">
           <button 
            type="button"
            onClick={handleResetCache}
            className="flex items-center gap-2 bg-white hover:bg-slate-50 px-4 py-2.5 rounded-xl text-[10px] font-black text-slate-600 transition-all border border-slate-200 shadow-sm active:scale-95"
           >
             <RefreshIcon size={12} />
             RESET CACHE
           </button>
           {isLocalMode && (
              <button 
                type="button"
                onClick={() => window.location.reload()}
                className="flex items-center gap-2 bg-indigo-600 px-5 py-2.5 rounded-xl text-xs font-bold text-white hover:bg-indigo-700 transition-all shadow-lg active:scale-95"
              >
                Coba Hubungkan DB
              </button>
           )}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link as ViewType)}
            className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-shadow cursor-pointer group"
          >
            <div className="flex justify-between items-start">
              <div className={`${stat.color} p-3 rounded-xl`}>
                {stat.icon}
              </div>
              <LinkIcon className="text-slate-300 group-hover:text-indigo-500 transition-colors w-4 h-4" />
            </div>
            <div className="mt-4">
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <h3 className="text-2xl font-bold text-slate-800 mt-1">{stat.value}</h3>
            </div>
          </div>
        ))}
      </div>

      {/* Manual Fix Area */}
      <div className="bg-rose-50 border border-rose-200 rounded-3xl p-6 md:p-8 shadow-sm">
         <div className="flex items-center gap-3 mb-6 text-rose-700">
           <div className="bg-rose-100 p-3 rounded-2xl">
              <WarningIcon size={28} />
           </div>
