ALTER TABLE IF EXISTS orders DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS customers DISABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS products DISABLE ROW LEVEL SECURITY;

-- 2. HAPUS SEMUA ATURAN LAMA YANG MEMBLOKIR
DROP POLICY IF EXISTS "Enable all access" ON orders;
DROP POLICY IF EXISTS "Enable all access" ON customers;
DROP POLICY IF EXISTS "Enable all access" ON products;

-- 3. BERIKAN IZIN AKSES PENUH KE PUBLIK (ANON)
GRANT ALL ON TABLE orders TO anon, authenticated, postgres;
GRANT ALL ON TABLE customers TO anon, authenticated, postgres;
GRANT ALL ON TABLE products TO anon, authenticated, postgres;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated, postgres;`.trim();

