import { supabase } from '../lib/supabase';
import { Customer, Product, Order } from '../types';

const ensureClient = () => {
  if (!supabase) throw new Error("Database belum terhubung. Periksa konfigurasi API Key di Vercel.");
};

// Mappings remains the same
const mapProductFromDB = (p: any): Product => ({
