  name: p.name,
  description: p.description,
  price_jakarta: p.priceJakarta,
  price_luar_kota: p.priceLuarKota
});

const mapOrderFromDB = (o: any): Order => ({
  id: o.id,
  invoiceNumber: o.invoice_number || 'INV-TEMP',
  customerId: o.customer_id || '',
  customerName: o.customer_name || 'Pelanggan',
  customerEmail: o.customer_email || '',
  customerType: o.customer_type || 'Jakarta',
  customerAddress: o.customer_address || '',
  orderDate: o.order_date || new Date().toISOString(),
  status: o.status || 'PENDING',
  items: o.items || [],
  subtotal: Number(o.subtotal || 0),
  downPayment: Number(o.down_payment || 0),
  payments: o.payments || [],
  total: Number(o.total || 0),
  notes: o.notes || ''
});

const mapOrderToDB = (o: Order) => ({
  id: o.id,
  invoice_number: o.invoiceNumber,
  customer_id: o.customerId,
  customer_name: o.customerName,
  customer_email: o.customerEmail,
  customer_type: o.customerType,
  customer_address: o.customerAddress,
  order_date: o.orderDate,
  status: o.status,
  items: o.items,
  subtotal: o.subtotal,
  down_payment: o.downPayment,
  payments: o.payments,
  total: o.total,
  notes: o.notes
});

export const dbService = {
  async getCustomers(): Promise<Customer[]> {
    ensureClient();
    const { data, error } = await supabase!.from('customers').select('*').order('name');
    if (error) throw error;
    return data || [];
  },

  async upsertCustomer(customer: Customer) {
    ensureClient();
    const { error } = await supabase!.from('customers').upsert(customer);
    if (error) throw error;
  },

  async deleteCustomer(id: string) {
    ensureClient();
    const { error } = await supabase!.from('customers').delete().eq('id', id);
    if (error) throw error;
  },

  async getProducts(): Promise<Product[]> {
    ensureClient();
    const { data, error } = await supabase!.from('products').select('*').order('name');
    if (error) throw error;
    return (data || []).map(mapProductFromDB);
  },

  async upsertProduct(product: Product) {
    ensureClient();
    const { error } = await supabase!.from('products').upsert(mapProductToDB(product));
    if (error) throw error;
  },

  async deleteProduct(id: string) {
    ensureClient();
    const { error } = await supabase!.from('products').delete().eq('id', id);
    if (error) throw error;
  },

  async getOrders(): Promise<Order[]> {
    ensureClient();
    const { data, error } = await supabase!.from('orders').select('*').order('order_date', { ascending: false });
    if (error) throw error;
    return (data || []).map(mapOrderFromDB);
  },

  async upsertOrder(order: Order) {
    ensureClient();
    const { error } = await supabase!.from('orders').upsert(mapOrderToDB(order));
    if (error) throw error;
  },

  async deleteOrder(id: string) {
    ensureClient();
    const { error } = await supabase!.from('orders').delete().eq('id', id);
    if (error) throw error;
  }
};

import { createClient } from '@supabase/supabase-js';

// Mengambil variabel lingkungan dengan fallback string kosong
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '';

// Deteksi kesalahan kunci secara spesifik (Stripe vs Supabase)
const isStripeKey = supabaseAnonKey.trim().startsWith('sb_publishable');
const hasConfig = supabaseUrl.length > 10 && supabaseAnonKey.length > 20;

if (isStripeKey) {
  console.error("KRITIS: Anda memasukkan Stripe Key ke variabel NEXT_PUBLIC_SUPABASE_ANON_KEY. Harap gunakan Supabase Anon Key (eyJ...).");
}

if (!hasConfig) {
  console.warn("KONFIGURASI: NEXT_PUBLIC_SUPABASE_URL atau NEXT_PUBLIC_SUPABASE_ANON_KEY belum terdeteksi di browser.");
}

/**
 * Client Supabase diinisialisasi secara malas (lazy) atau dengan pengecekan
 * agar tidak melempar error fatal saat aplikasi pertama kali dimuat.
 */
export const supabase = (hasConfig && !isStripeKey) 
  ? createClient(supabaseUrl, supabaseAnonKey, {
      auth: {
        persistSession: true,
        autoRefreshToken: true,
      }
    }) 
  : null;

/**
 * Fungsi pembantu untuk memvalidasi koneksi ke database.
 */
export const checkSupabaseConnection = async () => {
  if (!supabase) {
    if (isStripeKey) return { connected: false, message: "Kesalahan Kunci: Kunci Stripe digunakan untuk Supabase" };
    if (!hasConfig) return { connected: false, message: "Konfigurasi Database Belum Diset" };
    return { connected: false, message: "Inisialisasi Database Gagal" };
  }

  try {
    // Mencoba melakukan query minimal untuk memverifikasi JWT dan URL
    const { error } = await supabase.from('customers').select('id').limit(1);

    if (error) {
      if (error.message.includes('JWT') || error.code === 'PGRST301') {
        return { connected: false, message: "Kunci API Supabase Tidak Valid/Expired" };
      }
      if (error.message.includes('fetch')) {
        return { connected: false, message: "Gagal Menghubungi Server Supabase" };
      }
      throw error;
    }

    return { connected: true, message: "Terhubung ke Supabase Cloud" };
  } catch (err: any) {
    console.error("Koneksi Supabase Gagal:", err);
    return { connected: false, message: "Koneksi Error: " + (err.message || "Unknown") };
  }
};

import { React, useState, useEffect, useCallback } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, Calendar as CalendarIcon, Cloud, CloudOff, AlertCircle
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType, LocationType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';
import { checkSupabaseConnection } from './lib/supabase';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isOnline, setIsOnline] = useState<boolean | null>(null);
  const [connMessage, setConnMessage] = useState<string>('');

  const loadAllData = useCallback(async () => {
    setIsLoading(true);
    try {
      const conn = await checkSupabaseConnection();
      setIsOnline(conn.connected);
      setConnMessage(conn.message);

      if (conn.connected) {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      }
    } catch (e: any) {
      console.error("Data load error:", e);
      setIsOnline(false);
      setConnMessage(e.message || "Gagal memuat data");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadAllData();
  }, [loadAllData]);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
    window.scrollTo(0, 0);
  };

  // --- ACTIONS ---
  const addCustomer = async (c: Customer) => {
    try {
      await dbService.upsertCustomer(c);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const updateCustomer = async (c: Customer) => {
    try {
      await dbService.upsertCustomer(c);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const deleteCustomer = async (id: string) => {
    if (!window.confirm('Hapus pelanggan ini?')) return;
    try {
      await dbService.deleteCustomer(id);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const addProduct = async (p: Product) => {
    try {
      await dbService.upsertProduct(p);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const updateProduct = async (p: Product) => {
    try {
      await dbService.upsertProduct(p);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const deleteProduct = async (id: string) => {
    if (!window.confirm('Hapus barang ini?')) return;
    try {
      await dbService.deleteProduct(id);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const addOrder = async (o: Order) => {
    try {
      await dbService.upsertOrder(o);
      await loadAllData();
      setView('orders');
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const updateOrder = async (updated: Order) => {
    try {
      await dbService.upsertOrder(updated);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
  };

  const deleteOrder = async (id: string) => {
    if (!window.confirm('Hapus pesanan ini?')) return;
    try {
      await dbService.deleteOrder(id);
      await loadAllData();
    } catch (e: any) { alert("Error: " + e.message); }
