const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

// Deteksi kesalahan kunci secara spesifik
if (supabaseAnonKey && (supabaseAnonKey.startsWith('sb_publishable') || supabaseAnonKey.startsWith('pk_'))) {
  console.error("CRITICAL ERROR: Anda memasukkan Stripe Key ke dalam Supabase Anon Key! Gunakan key yang diawali 'eyJ...'");
}

if (!supabaseUrl || !supabaseAnonKey) {
  console.error("Supabase environment variables are missing! Pastikan NEXT_PUBLIC_SUPABASE_URL dan NEXT_PUBLIC_SUPABASE_ANON_KEY sudah diset di environment variables.");
}

export const supabase = (supabaseUrl && supabaseAnonKey) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

export const checkSupabaseConnection = async () => {
  try {
    if (!supabase) {
      return { connected: false, message: "Konfigurasi Database Belum Lengkap" };
    }

    // Test query sederhana ke tabel customers
    const { error } = await supabase.from('customers').select('id').limit(1);

    if (error) {
      if (error.message.includes('JWT')) {
        return { connected: false, message: "Kunci API (JWT) Supabase Salah" };
      }
      throw error;
    }

    return { connected: true, message: "Terhubung ke Supabase Cloud" };
  } catch (err: any) {
    console.error("Connection Check Failed:", err);
    return { connected: false, message: "Gagal terhubung: " + err.message };
  }
};

