import { GoogleGenAI } from "@google/genai";
import { Order } from "../types";

/**
 * Mendapatkan ringkasan pesanan menggunakan Gemini AI.
 * Fungsi ini dirancang untuk aman dari error inisialisasi jika API Key tidak ada.
 */
export const getSmartOrderSummary = async (order: Order): Promise<string> => {
  try {
    // Mengambil API Key dari environment variable
    const apiKey = process.env.API_KEY;

    // Validasi ketat: Jika key tidak ada atau berupa string "undefined" (sering terjadi pada build tools)
    if (!apiKey || apiKey === "undefined" || apiKey.trim() === "") {
      console.warn("Gemini AI: API Key tidak ditemukan atau kosong. Ringkasan otomatis dinonaktifkan.");
      return "Ringkasan AI belum tersedia karena konfigurasi API Key belum lengkap.";
    }

    // Inisialisasi SDK hanya jika kunci valid
    const ai = new GoogleGenAI({ apiKey: apiKey.trim() });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan ringkasan singkat dan profesional untuk pesanan berikut dalam Bahasa Indonesia:
      Nomor Invoice: ${order.invoiceNumber}
      Pelanggan: ${order.customerName}
      Item: ${order.items.map(i => `${i.name} (${i.quantity}x)`).join(', ')}
      Total Tagihan: Rp ${order.total.toLocaleString()}
      Sisa Bayar: Rp ${(order.total - (order.downPayment || 0)).toLocaleString()}

      Berikan 1 kalimat saran untuk meningkatkan kepuasan pelanggan ini.`,
      config: {
        temperature: 0.7,
      }
    });

    // Mengambil teks hasil generate. Properti .text langsung diakses (bukan method).
    const resultText = response.text;
    return resultText || "Gagal menghasilkan ringkasan.";
  } catch (error: any) {
    // Menangkap error spesifik dari SDK atau jaringan
    console.error("Gemini AI Service Error:", error);

    if (error.message?.includes("API key")) {
      return "Error: Konfigurasi API Key Gemini tidak valid.";
    }

    return "Layanan ringkasan AI sedang tidak dapat dijangkau.";
  }
};

