const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '';

// Deteksi kesalahan kunci secara spesifik untuk membantu debugging user
if (supabaseAnonKey && (supabaseAnonKey.startsWith('sb_publishable') || supabaseAnonKey.startsWith('pk_'))) {
  console.error("KONFIGURASI SALAH: Anda memasukkan Stripe Key ke dalam Supabase Anon Key! Harap gunakan Supabase Anon Key (diawali 'eyJ...').");
}

if (!supabaseUrl || !supabaseAnonKey) {
  console.warn("KONFIGURASI HILANG: NEXT_PUBLIC_SUPABASE_URL atau NEXT_PUBLIC_SUPABASE_ANON_KEY tidak ditemukan.");
}

/**
 * Inisialisasi client Supabase. 
 * Kita menggunakan pengecekan eksistensi URL agar tidak melempar error saat boot up.
 */
export const supabase = (supabaseUrl && supabaseAnonKey && supabaseUrl.startsWith('http')) 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

/**
 * Mengecek status koneksi ke database.
 */
export const checkSupabaseConnection = async () => {
  if (!supabase) {
    return { 
      connected: false, 
      message: "Database belum terhubung. Periksa variabel NEXT_PUBLIC_SUPABASE_URL di dashboard deployment." 
    };
  }

  try {
    // Test query minimal ke tabel customers
    const { error } = await supabase.from('customers').select('id').limit(1);

    if (error) {
      if (error.message.includes('JWT') || error.code === 'PGRST301') {
        return { connected: false, message: "Kunci API (JWT) Supabase tidak valid." };
      }
      throw error;
    }

    return { connected: true, message: "Terhubung ke database." };
  } catch (err: any) {
    console.error("Database Connection Check Error:", err);
    return { connected: false, message: "Gagal terhubung ke database: " + (err.message || "Unknown error") };
  }
};

import { Customer, Product, Order } from '../types';

const STORAGE_KEYS = {
  CUSTOMERS: 'orderpro_customers',
  PRODUCTS: 'orderpro_products',
  ORDERS: 'orderpro_orders'
};

// Helper untuk membaca dari localStorage
const getData = <T>(key: string): T[] => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : [];
};

// Helper untuk menulis ke localStorage
const saveData = <T>(key: string, data: T[]) => {
  localStorage.setItem(key, JSON.stringify(data));
};

export const dbService = {
  // --- CUSTOMERS ---
  async getCustomers(): Promise<Customer[]> {
    return getData<Customer>(STORAGE_KEYS.CUSTOMERS);
  },

  async upsertCustomer(customer: Customer) {
    const data = getData<Customer>(STORAGE_KEYS.CUSTOMERS);
    const index = data.findIndex(c => c.id === customer.id);
    if (index >= 0) {
      data[index] = customer;
    } else {
      data.push(customer);
    }
    saveData(STORAGE_KEYS.CUSTOMERS, data);
  },

  async deleteCustomer(id: string) {
    const data = getData<Customer>(STORAGE_KEYS.CUSTOMERS);
    saveData(STORAGE_KEYS.CUSTOMERS, data.filter(c => c.id !== id));
  },

  // --- PRODUCTS ---
  async getProducts(): Promise<Product[]> {
    return getData<Product>(STORAGE_KEYS.PRODUCTS);
  },

  async upsertProduct(product: Product) {
    const data = getData<Product>(STORAGE_KEYS.PRODUCTS);
    const index = data.findIndex(p => p.id === product.id);
    if (index >= 0) {
      data[index] = product;
    } else {
      data.push(product);
    }
    saveData(STORAGE_KEYS.PRODUCTS, data);
  },

  async deleteProduct(id: string) {
    const data = getData<Product>(STORAGE_KEYS.PRODUCTS);
    saveData(STORAGE_KEYS.PRODUCTS, data.filter(p => p.id !== id));
  },

  // --- ORDERS ---
  async getOrders(): Promise<Order[]> {
    const orders = getData<Order>(STORAGE_KEYS.ORDERS);
    return orders.sort((a, b) => new Date(b.orderDate).getTime() - new Date(a.orderDate).getTime());
  },

  async upsertOrder(order: Order) {
    const data = getData<Order>(STORAGE_KEYS.ORDERS);
    const index = data.findIndex(o => o.id === order.id);
    if (index >= 0) {
      data[index] = order;
    } else {
      data.push(order);
    }
    saveData(STORAGE_KEYS.ORDERS, data);
  },

  async deleteOrder(id: string) {
    const data = getData<Order>(STORAGE_KEYS.ORDERS);
    saveData(STORAGE_KEYS.ORDERS, data.filter(o => o.id !== id));
  }
};

