import { GoogleGenAI } from "@google/genai";
import { Order } from "../types";

/**
 * Fungsi pembantu untuk mengambil API Key dengan aman di lingkungan browser.
 */
const getSafeApiKey = (): string | undefined => {
  try {
    // Mengecek apakah variabel process tersedia (untuk menghindari error 'process is not defined')
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      const key = process.env.API_KEY;
      if (key && key !== "undefined" && key.trim() !== "") {
        return key.trim();
      }
    }
  } catch (e) {
    console.error("Gagal mengakses environment variables:", e);
  }
  return undefined;
};

export const getSmartOrderSummary = async (order: Order): Promise<string> => {
  try {
    const apiKey = getSafeApiKey();

    if (!apiKey) {
      console.warn("Gemini AI: API Key tidak ditemukan. Fitur ringkasan otomatis dinonaktifkan.");
      return "Fitur ringkasan AI membutuhkan API_KEY yang valid di environment variables.";
    }

    // Hanya inisialisasi jika kunci dipastikan ada
    const ai = new GoogleGenAI({ apiKey });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Buat ringkasan pesanan singkat (max 2 kalimat) untuk:
      Invoice: ${order.invoiceNumber}
      Pelanggan: ${order.customerName}
      Total: Rp ${order.total.toLocaleString()}
      Sisa Bayar: Rp ${(order.total - (order.downPayment || 0)).toLocaleString()}
      Item: ${order.items.map(i => i.name).join(', ')}`,
      config: {
        temperature: 0.5,
      }
    });

    return response.text || "Ringkasan tidak tersedia.";
  } catch (error: any) {
    console.error("Gemini Service Error:", error);
    return "Layanan AI sedang tidak tersedia atau kuota habis.";
  }
};

