      config: {
        temperature: 0.7,
      }
    });

    return response.text || "Ringkasan pesanan telah dibuat.";
  } catch (error: any) {
    console.warn("Gemini AI Summary skipped:", error.message);
    return "Ringkasan otomatis tidak tersedia (Cek API_KEY).";
  }
};

