import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, Cloud, Wifi, AlertCircle, RefreshCw
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType, LocationType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import { dbService } from './services/dbService';
import { checkSupabaseConnection } from './lib/supabase';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [isLoading, setIsLoading] = useState(true);
  const [loadTimeout, setLoadTimeout] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [dbStatus, setDbStatus] = useState({ connected: false, message: 'Menghubungkan...' });
  const loadAttempted = useRef(false);

  const loadAllData = useCallback(async () => {
    // Hindari double loading
    if (loadAttempted.current && !isLoading) return;
    loadAttempted.current = true;

    setIsLoading(true);
    setLoadTimeout(false);

    // Timeout proteksi 10 detik
    const timer = setTimeout(() => {
      setLoadTimeout(true);
    }, 10000);

    try {
      const connection = await checkSupabaseConnection();
      setDbStatus(connection);

      if (connection.connected) {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers().catch(e => { console.error("Customers fail", e); return []; }),
          dbService.getProducts().catch(e => { console.error("Products fail", e); return []; }),
          dbService.getOrders().catch(e => { console.error("Orders fail", e); return []; })
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
      }
    } catch (e: any) {
      console.error("Critical Data load error:", e);
      setDbStatus({ connected: false, message: "Koneksi Cloud Bermasalah" });
    } finally {
      clearTimeout(timer);
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    loadAllData();
  }, [loadAllData]);

  const setView = (view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
    window.scrollTo(0, 0);
  };

  // --- ACTIONS ---
  const handleAction = async (action: () => Promise<any>) => {
    try {
      await action();
      await loadAllData();
    } catch (err: any) {
      alert("Terjadi kesalahan: " + (err.message || "Gagal menyimpan ke cloud"));
    }
  };

  const addCustomer = (c: Customer) => handleAction(() => dbService.upsertCustomer(c));
  const updateCustomer = (c: Customer) => handleAction(() => dbService.upsertCustomer(c));
  const deleteCustomer = (id: string) => {
    if (window.confirm('Hapus pelanggan ini?')) handleAction(() => dbService.deleteCustomer(id));
  };

  const addProduct = (p: Product) => handleAction(() => dbService.upsertProduct(p));
  const updateProduct = (p: Product) => handleAction(() => dbService.upsertProduct(p));
  const deleteProduct = (id: string) => {
    if (window.confirm('Hapus barang ini?')) handleAction(() => dbService.deleteProduct(id));
  };

  const addOrder = (o: Order) => handleAction(async () => {
    await dbService.upsertOrder(o);
    setView('orders');
  });

  const updateOrder = (updated: Order) => handleAction(() => dbService.upsertOrder(updated));
  const deleteOrder = (id: string) => {
    if (window.confirm('Hapus pesanan ini?')) handleAction(() => dbService.deleteOrder(id));
  };

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (isLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-8 text-center">
      <div className="relative">
        <div className="w-20 h-20 border-4 border-slate-200 border-t-indigo-600 rounded-full animate-spin"></div>
        <div className="absolute inset-0 flex items-center justify-center">
          <Cloud size={24} className="text-indigo-400" />
        </div>
      </div>
      <h2 className="mt-8 text-xl font-black text-slate-800 tracking-tight">Menghubungkan...</h2>
      <p className="mt-2 text-slate-500 font-medium text-sm max-w-xs leading-relaxed">Aplikasi sedang menyelaraskan data.</p>

      {loadTimeout && (
        <div className="mt-12 p-6 bg-white rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/50 animate-in zoom-in-95 duration-500 max-w-sm">
          <div className="flex items-center gap-3 text-amber-600 mb-4 justify-center">
            <AlertCircle size={20} />
            <span className="font-black text-xs uppercase tracking-widest">Koneksi Lambat</span>
          </div>
          <p className="text-slate-500 text-xs mb-6 font-medium">Sinkronisasi membutuhkan waktu lebih lama. Coba muat ulang atau lewati untuk masuk.</p>
          <div className="flex gap-3">
            <button onClick={() => location.reload()} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all">
              <RefreshCw size={14} /> Muat Ulang
            </button>
            <button onClick={() => setIsLoading(false)} className="flex-1 bg-slate-100 text-slate-600 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-200 transition-all">
              Lewati
            </button>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <header className="md:hidden bg-slate-900 text-white p-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg"><Package size={20} /></div>
          <span className="font-black text-sm uppercase tracking-tight">Buku PO <span className="text-indigo-400">Online</span></span>
        </div>
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 hover:bg-slate-800 rounded-lg transition-colors">
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden animate-in fade-in duration-300" onClick={() => setIsMobileMenuOpen(false)} />}

      <aside className={`w-72 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ease-in-out ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen`}>
        <div className="p-8 hidden md:flex flex-col gap-1 border-b border-slate-800">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-500/20"><Package className="text-white w-6 h-6" /></div>
            <span className="text-xl font-black text-white tracking-tighter">Buku PO <span className="text-indigo-400">Online</span></span>
          </div>
          <div className="flex items-center gap-2 mt-4 px-1">
             <Wifi size={12} className={dbStatus.connected ? "text-emerald-500" : "text-rose-500"} />
             <span className={`text-[10px] font-black uppercase tracking-widest ${dbStatus.connected ? "text-slate-400" : "text-rose-400"}`}>
               {dbStatus.message}
             </span>
          </div>
        </div>
        <nav className="flex-1 p-5 space-y-1.5 overflow-y-auto no-scrollbar mt-4">
          <NavItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Master Data</div>
          <NavItem icon={<Users size={20} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={20} />} label="Katalog Barang" active={state.view === 'products'} onClick={() => setView('products')} />
          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Transaksi</div>
          <NavItem icon={<ShoppingCart size={20} />} label="Order Masuk" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={20} />} label="Analisa Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />
        </nav>
        <div className="p-6 border-t border-slate-800">
          {/* Section Database Online telah dihapus sesuai permintaan */}
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="hidden md:flex bg-white/80 backdrop-blur-md border-b h-20 items-center px-10 sticky top-0 z-30 justify-between">
           <div>
             <h2 className="text-xl font-black text-slate-900 capitalize tracking-tight">{state.view.replace('_', ' ')}</h2>
           </div>
           {!dbStatus.connected && (
             <div className="bg-rose-50 text-rose-600 px-4 py-2 rounded-xl text-xs font-bold border border-rose-100 flex items-center gap-2 animate-pulse">
               <Wifi size={14} /> Terputus dari Server
             </div>
           )}
           <div className="flex items-center gap-6">
             <div className="text-right">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Hari Ini</p>
               <p className="text-xs font-bold text-slate-700">
                 {new Date().toLocaleDateString('id-ID', { weekday: 'long', day: 'numeric', month: 'long' })}
               </p>
             </div>
           </div>
        </header>

        <div className="flex-1 overflow-y-auto bg-slate-50/50">
          <div className="p-4 md:p-10 max-w-7xl mx-auto">
            {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} onDeleteOrder={deleteOrder} />}
            {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
            {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
            {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
            {state.view === 'reports' && <Reports state={state} />}
            {state.view === 'invoice_detail' && state.activeOrder && (
              <div className="animate-in fade-in zoom-in-95 duration-500 pb-20">
                <button onClick={() => setView('orders')} className="group flex items-center gap-3 text-slate-500 hover:text-indigo-600 mb-8 font-black text-[10px] uppercase tracking-[0.2em] bg-white px-6 py-3 rounded-2xl shadow-sm border border-slate-100 transition-all hover:shadow-indigo-100">
                  <span>←</span> Kembali ke Daftar Order
                </button>
                <InvoiceView order={state.activeOrder} />
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
