import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, User, 
  Package, Check, CreditCard, Edit3, X, Calendar
} from 'lucide-react';
import { AppState, Order, OrderItem, Product, OrderStatus, LocationType, PaymentRecord } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => void;
  onUpdateOrder: (o: Order) => void;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onUpdateOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);

  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');
  const [orderDate, setOrderDate] = useState(new Date().toISOString().split('T')[0]);

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);

  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId || '');
      setOrderItems(editingOrder.items ? editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })) : []);
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setOrderDate(new Date(editingOrder.orderDate).toISOString().split('T')[0]);
      setIsFormOpen(true);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? (product.priceLuarKota || 0) : (product.priceJakarta || 0);
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * item.qty);
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + (p.amount || 0), 0);
  }, [payments]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedCustomerId || orderItems.length === 0) {
      alert("Mohon pilih pelanggan dan minimal satu barang.");
      return;
    }

    const items: OrderItem[] = orderItems.map(oi => {
      const p = state.products.find(product => product.id === oi.productId)!;
      const price = selectedCustomer ? calculateItemPrice(p, selectedCustomer.type) : 0;
      return {
        id: Math.random().toString(36).substr(2, 9),
        productId: p.id,
        name: p.name,
        quantity: oi.qty,
        unitPrice: price
      };
    });

    const orderData: Order = {
      id: editingOrder ? editingOrder.id : Math.random().toString(36).substr(2, 9),
      invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
      customerId: selectedCustomerId,
      customerName: selectedCustomer ? selectedCustomer.name : (editingOrder ? editingOrder.customerName : 'Pelanggan'),
      customerEmail: selectedCustomer ? selectedCustomer.email : (editingOrder ? editingOrder.customerEmail : ''),
      customerType: selectedCustomer ? selectedCustomer.type : (editingOrder ? editingOrder.customerType : LocationType.JAKARTA),
      customerAddress: selectedCustomer ? selectedCustomer.address : (editingOrder ? editingOrder.customerAddress : ''),
      orderDate: new Date(orderDate).toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: calculatedSubtotal,
      downPayment: currentTotalPaid,
      payments,
      total: calculatedSubtotal - currentTotalPaid,
      notes
    };

    if (editingOrder) {
      onUpdateOrder(orderData);
    } else {
      onAddOrder(orderData);
    }
    resetForm();
  };

  const addPayment = () => {
    if (newPaymentAmount <= 0) return;
    const newRecord: PaymentRecord = {
      id: Math.random().toString(36).substr(2, 9),
      amount: newPaymentAmount,
      date: new Date().toISOString(),
      note: newPaymentNote || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
    };
    setPayments([...payments, newRecord]);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setOrderDate(new Date().toISOString().split('T')[0]);
    setShowPaymentInput(false);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-slate-800">Transaksi Pesanan</h2>
          <p className="text-slate-500 text-xs md:text-sm font-medium">Monitoring dan pembuatan invoice</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="w-full sm:w-auto bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-bold text-sm flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={18} /> Order Baru
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-3xl shadow-2xl border border-slate-100 p-6 md:p-8 animate-in slide-in-from-top-4 duration-500">
           <div className="flex justify-between items-center mb-8">
             <h3 className="text-lg md:text-xl font-black text-slate-900 tracking-tight">{editingOrder ? 'Edit Pesanan' : 'Buat Pesanan Baru'}</h3>
             <button onClick={resetForm} className="p-2 hover:bg-slate-50 rounded-full text-slate-400 transition-colors"><X size={20}/></button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-8">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <Calendar size={14} className="text-indigo-500"/> 1. Tanggal Pesanan
                    </h3>
                    <input 
                      required
                      type="date"
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-bold text-sm"
                      value={orderDate}
                      onChange={e => setOrderDate(e.target.value)}
                    />
                  </div>

                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <User size={14} className="text-indigo-500"/> 2. Pilih Pelanggan
                    </h3>
                    <select 
                      required
                      className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 bg-slate-50 outline-none font-bold text-sm appearance-none cursor-pointer"
                      value={selectedCustomerId}
                      onChange={e => setSelectedCustomerId(e.target.value)}
                    >
                      <option value="">-- Cari Pelanggan --</option>
                      {state.customers.map(c => (
                        <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="space-y-4">
                   <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <Package size={14} className="text-indigo-500"/> 3. Item Pesanan
                  </h3>
                  <div className="space-y-2 max-h-[300px] overflow-y-auto pr-2 no-scrollbar border p-2 rounded-2xl bg-slate-50/50">
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-3 rounded-2xl border transition-all ${
                          existing ? 'bg-white border-indigo-200 shadow-sm' : 'bg-white/50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-4">
                             <p className="text-xs font-bold text-slate-800 truncate">{p.name}</p>
                             <p className="text-[9px] text-slate-400 font-black uppercase tracking-wider">
                               Rp {(selectedCustomer ? calculateItemPrice(p, selectedCustomer.type) : p.priceJakarta).toLocaleString()}
                             </p>
                           </div>
                           <div className="flex items-center gap-3 shrink-0">
                             {existing && (
                               <input 
                                 type="number"
                                 min="1"
                                 className="w-12 px-1 py-1.5 rounded-lg border border-indigo-200 text-xs font-black text-center outline-none bg-indigo-50 text-indigo-700"
                                 value={existing.qty}
                                 onChange={e => {
                                   const val = parseInt(e.target.value) || 1;
                                   setOrderItems(orderItems.map(i => i.productId === p.id ? { ...i, qty: val } : i));
                                 }}
                               />
                             )}
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-8 h-8 rounded-xl flex items-center justify-center transition-all ${
                                 existing ? 'bg-indigo-600 text-white shadow-md' : 'bg-white text-slate-300 border border-slate-200 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={16} /> : <Plus size={16} />}
                             </button>
                           </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-100">
                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <CreditCard size={14} className="text-indigo-500"/> 4. Pembayaran
                    </h3>
                    <button 
                      type="button" 
                      onClick={() => setShowPaymentInput(!showPaymentInput)}
                      className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl border border-indigo-100 hover:bg-indigo-100 transition-all"
                    >
                      {showPaymentInput ? 'Batal' : '+ Tambah Pembayaran'}
                    </button>
                  </div>

                  {showPaymentInput && (
                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-200 space-y-3 shadow-inner animate-in fade-in zoom-in-95 duration-200">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <div className="relative">
                           <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-[10px] font-black">RP</span>
                           <input 
                            type="number"
                            placeholder="Nominal"
                            className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-slate-200 text-sm font-bold outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
                            value={newPaymentAmount || ''}
                            onChange={e => setNewPaymentAmount(Number(e.target.value))}
                          />
                        </div>
                        <input 
                          type="text"
                          placeholder="Ket: DP 1, Pelunasan, dll"
                          className="px-4 py-2.5 rounded-xl border border-slate-200 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 bg-white"
                          value={newPaymentNote}
                          onChange={e => setNewPaymentNote(e.target.value)}
                        />
                      </div>
                      <button 
                        type="button" 
                        onClick={addPayment}
                        className="w-full bg-slate-900 text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all"
                      >
                        Simpan Pembayaran
                      </button>
                    </div>
                  )}

                  <div className="space-y-2">
                    {payments.map((p) => (
                      <div key={p.id} className="flex justify-between items-center p-4 bg-white border border-slate-100 rounded-2xl shadow-sm">
                        <div className="flex items-center gap-4">
                          <div className="w-8 h-8 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600 shadow-sm">
                            <Check size={14}/>
                          </div>
                          <div>
                            <p className="text-xs font-black text-slate-800">{p.note}</p>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{new Date(p.date).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <p className="text-sm font-black text-slate-800">Rp {p.amount.toLocaleString()}</p>
                      </div>
                    ))}
                    {payments.length === 0 && <p className="text-center py-6 text-[10px] text-slate-300 font-black uppercase tracking-widest italic border border-dashed rounded-2xl">Belum ada rincian bayar.</p>}
                  </div>
                </div>

                <div className="space-y-2">
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Catatan Tambahan</h3>
                  <textarea 
                    className="w-full px-5 py-4 rounded-3xl border border-slate-200 bg-slate-50 outline-none text-sm font-medium h-32 md:h-44 focus:ring-2 focus:ring-indigo-500 transition-all shadow-inner"
                    placeholder="Instruksi khusus pesanan ini..."
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                  />
                </div>
             </div>

             <div className="flex flex-col md:flex-row md:items-center justify-between bg-slate-900 p-6 md:p-10 rounded-[2.5rem] text-white gap-6 shadow-2xl">
               <div>
                  <p className="text-slate-400 text-[10px] mb-2 font-black uppercase tracking-[0.2em] opacity-60">Subtotal: Rp {calculatedSubtotal.toLocaleString()}</p>
                  <h4 className="text-2xl md:text-4xl font-black tracking-tighter">
                    Sisa: <span className="text-indigo-400">Rp {(calculatedSubtotal - currentTotalPaid).toLocaleString()}</span>
                  </h4>
               </div>
               <button 
                type="submit"
                disabled={!selectedCustomerId || orderItems.length === 0}
                className="w-full md:w-auto bg-indigo-600 hover:bg-indigo-700 disabled:opacity-20 disabled:cursor-not-allowed text-white px-12 py-4 rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-xl shadow-indigo-500/20"
               >
                 {editingOrder ? 'Update Pesanan' : 'Selesaikan Order'}
               </button>
             </div>
           </form>
        </div>
      )}

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden overflow-x-auto">
        <table className="w-full text-left min-w-[700px]">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
            <tr>
              <th className="px-6 py-5">No. Invoice</th>
              <th className="px-6 py-5">Pelanggan</th>
              <th className="px-6 py-5 text-right">Total</th>
              <th className="px-6 py-5 text-right">Sisa Bayar</th>
              <th className="px-6 py-5 text-center">Opsi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {state.orders.map(o => (
              <tr key={o.id} className="hover:bg-slate-50/50 transition-all group">
                <td className="px-6 py-5">
                  <p className="text-sm font-black text-slate-800">{o.invoiceNumber}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{new Date(o.orderDate).toLocaleDateString('id-ID', { dateStyle: 'medium' })}</p>
                </td>
                <td className="px-6 py-5">
                  <p className="text-sm font-bold text-slate-700 truncate max-w-[150px]">{o.customerName || 'N/A'}</p>
                  <span className="inline-flex px-1.5 py-0.5 rounded-lg bg-indigo-50 text-indigo-500 text-[8px] font-black uppercase tracking-wider">
                    {o.customerType}
                  </span>
                </td>
                <td className="px-6 py-5 text-right text-sm font-bold text-slate-600">
                  Rp {(o.subtotal || 0).toLocaleString()}
                </td>
                <td className="px-6 py-5 text-right">
                  <div className={`text-sm font-black ${(o.total || 0) <= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>
                    Rp {(o.total || 0).toLocaleString()}
                    {(o.total || 0) <= 0 && <span className="ml-1 text-[8px] uppercase tracking-widest opacity-60">Lunas</span>}
                  </div>
                </td>
                <td className="px-6 py-5">
                  <div className="flex justify-center gap-2">
                    <button 
                      type="button"
                      onClick={(e) => { e.preventDefault(); e.stopPropagation(); onViewInvoice(o); }}
                      className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                      title="Lihat Nota"
                    >
                      <Eye size={18} />
                    </button>
                    <button 
                      type="button"
                      onClick={(e) => { e.preventDefault(); e.stopPropagation(); setEditingOrder(o); }}
                      className="p-2 text-slate-400 hover:text-amber-500 hover:bg-amber-50 rounded-xl transition-all"
                      title="Edit Pesanan"
                    >
                      <Edit3 size={18} />
                    </button>
                    <button 
                      type="button"
                      onClick={(e) => { e.preventDefault(); e.stopPropagation(); onDeleteOrder(o.id); }}
                      className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"
                      title="Hapus Pesanan"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
             {state.orders.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-24 text-center text-slate-400">
                  <ShoppingCart size={48} className="mx-auto mb-4 opacity-10" />
                  <p className="text-sm font-bold uppercase tracking-widest opacity-50">Belum ada riwayat transaksi.</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default OrderManager;

import React, { useRef, useState, useEffect } from 'react';
import { Download, Share2, Sparkles, Image as ImageIcon, FileText } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    const fetchSummary = async () => {
      setIsAiLoading(true);
      const summary = await getSmartOrderSummary(order);
      setAiSummary(summary);
      setIsAiLoading(false);
    };
    fetchSummary();
  }, [order]);

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2 });
    const link = document.createElement('a');
    link.download = `${order.invoiceNumber}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    const canvas = await html2canvas(invoiceRef.current, { scale: 2, useCORS: true });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`${order.invoiceNumber}.pdf`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 pb-12">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between">
            <h3 className="text-xl font-bold text-slate-800">Preview Nota</h3>
            <div className="flex gap-2">
                <button onClick={handleDownloadJPG} className="px-4 py-2 bg-white border border-slate-200 rounded-xl text-slate-600 hover:bg-slate-50 flex items-center gap-2 text-xs font-bold transition-all"><ImageIcon className="w-4 h-4" />JPG</button>
                <button onClick={handleDownloadPDF} className="px-4 py-2 bg-indigo-600 text-white border border-indigo-600 rounded-xl hover:bg-indigo-700 flex items-center gap-2 text-xs font-bold transition-all shadow-lg shadow-indigo-200"><FileText className="w-4 h-4" />Download PDF</button>
            </div>
        </div>

        <div ref={invoiceRef} className="bg-white rounded-lg shadow-2xl p-10 md:p-16 text-slate-800 border border-slate-100 overflow-hidden" style={{ width: '100%', maxWidth: '800px', margin: '0 auto' }}>
          <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-12">
            <div>
              <h1 className="text-4xl font-black text-slate-900 tracking-tighter">NOTA</h1>
              <p className="text-slate-400 mt-2 font-bold tracking-widest uppercase text-xs">NO. {order.invoiceNumber}</p>
            </div>
            <div className="text-right">
                <p className="text-xs font-bold text-slate-300 uppercase">Tanggal</p>
                <p className="font-bold text-slate-800">{new Date(order.orderDate).toLocaleDateString('id-ID', { dateStyle: 'long' })}</p>
            </div>
          </div>

          <div className="mb-16">
            <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-4">Kepada</h4>
            <p className="text-xl font-bold text-slate-900">{order.customerName}</p>
            {order.customerAddress && <div className="text-sm text-slate-500 mt-2 whitespace-pre-wrap max-w-sm">{order.customerAddress}</div>}
          </div>

          <table className="w-full mb-12">
            <thead>
              <tr className="border-b border-slate-200 text-left">
                <th className="py-4 text-xs font-black uppercase tracking-widest">Nama Barang</th>
                <th className="py-4 px-4 text-xs font-black uppercase text-center">Qty</th>
                <th className="py-4 text-xs font-black uppercase text-right">Harga</th>
                <th className="py-4 text-xs font-black uppercase text-right">Subtotal</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {order.items.map((item) => (
                <tr key={item.id}>
                  <td className="py-5 pr-4 text-sm font-bold text-slate-800">{item.name}</td>
                  <td className="py-5 px-4 text-sm text-center text-slate-600">{item.quantity}</td>
                  <td className="py-5 text-sm text-right text-slate-600">Rp {item.unitPrice.toLocaleString()}</td>
                  <td className="py-5 text-sm text-right font-bold text-slate-900">Rp {(item.quantity * item.unitPrice).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="flex justify-end">
            <div className="w-full max-w-[320px] space-y-4">
              <div className="flex justify-between text-sm">
                <span className="text-slate-400 font-bold uppercase text-[10px]">Subtotal Pesanan</span>
                <span className="text-slate-800 font-bold">Rp {order.subtotal.toLocaleString()}</span>
              </div>

              {order.payments && order.payments.length > 0 && (
                <div className="space-y-2 pt-2">
                  <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Rincian Pembayaran:</p>
                  {order.payments.map((p, idx) => {
                    const label = order.payments.length === 1 ? "DP" : `DP ${idx + 1}`;
                    return (
                      <div key={p.id} className="flex justify-between text-[11px]">
                        <span className="text-emerald-500 font-medium italic">{label}</span>
                        <span className="text-emerald-600 font-bold">- Rp {p.amount.toLocaleString()}</span>
                      </div>
                    );
                  })}
                  <div className="pt-2 border-t border-slate-100 flex justify-between text-xs">
                     <span className="text-slate-400 font-bold">Total Terbayar</span>
                     <span className="text-emerald-600 font-black">Rp {order.downPayment.toLocaleString()}</span>
                  </div>
                </div>
              )}

              <div className="pt-6 border-t-2 border-slate-900">
                <div className="flex justify-between items-baseline">
                  <span className="text-xs font-black text-slate-900 uppercase">Sisa Tagihan</span>
                  <span className="text-3xl font-black text-indigo-600">Rp {order.total.toLocaleString()}</span>
                </div>
              </div>
            </div>
          </div>

          <div className="mt-24 pt-12 border-t border-slate-100 text-center">
             {order.notes && (
               <div className="mb-8 text-left p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Catatan:</p>
                  <p className="text-sm text-slate-600 italic">"{order.notes}"</p>
               </div>
             )}
             <p className="text-sm font-black text-slate-900 uppercase tracking-widest">Terima kasih</p>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-2xl">
          <div className="flex items-center gap-2 mb-6"><Sparkles className="w-5 h-5 text-indigo-400" /><h4 className="font-black text-lg uppercase">Ringkasan AI</h4></div>
          {isAiLoading ? <div className="space-y-4 animate-pulse"><div className="h-3 bg-slate-800 rounded-full w-full"></div><div className="h-3 bg-slate-800 rounded-full w-5/6"></div></div> : (
            <p className="text-sm text-slate-300 italic pl-4 border-l-2 border-indigo-500">{aiSummary}</p>
          )}
        </div>
        <button className="w-full flex items-center justify-center gap-3 bg-emerald-500 text-white py-3 rounded-2xl font-bold text-sm hover:bg-emerald-600 transition-all"><Share2 size={18} /> Kirim WhatsApp</button>
      </div>
    </div>
  );
};

